const f = n => n?.toLocaleString("en-GB",{minimumFractionDigits:2,maximumFractionDigits:2});

// ── VAT helpers (all prices ex. VAT; 20% VAT added at checkout/billing)

const VAT_RATE=0.20;

const vatOf=p=>Math.round(p*VAT_RATE*100)/100;

const incVAT=p=>Math.round(p*1.20*100)/100;

const fVAT=p=>`£${f(incVAT(p))}`; // formatted inc. VAT

const VATBadge=()=><span style={{fontSize:9,fontWeight:700,padding:"1px 5px",borderRadius:4,background:"rgba(245,158,11,0.06)",color:"#F59E0B",marginLeft:4}}>ex. VAT</span>;

const VATBreakdown=({price,style:sx})=><div style={{fontSize:11,color:"#CBD5E1",lineHeight:1.8,...sx}}>

  <div style={{display:"flex",justifyContent:"space-between"}}><span>Subtotal (ex. VAT)</span><span style={{fontFamily:"ui-monospace,monospace"}}>£{f(price)}</span></div>

  <div style={{display:"flex",justifyContent:"space-between"}}><span>VAT (20%)</span><span style={{fontFamily:"ui-monospace,monospace"}}>£{f(vatOf(price))}</span></div>

  <div style={{display:"flex",justifyContent:"space-between",fontWeight:800,color:"#F8FAFC",marginTop:3,paddingTop:3,borderTop:"1px solid rgba(80,140,255,0.15)"}}><span>Total (inc. VAT)</span><span style={{fontFamily:"ui-monospace,monospace"}}>{fVAT(price)}</span></div>

</div>;

function Btn({children,onClick,v="ghost",disabled,full,style:sx}){
  const variants={
    ghost:   {bg:"rgba(80,140,255,0.06)",  b:"1px solid rgba(80,140,255,0.18)",   c:"#CBD5E1", shadow:"none"},
    primary: {bg:"linear-gradient(135deg,#006DFF,#0057CC)", b:"1px solid rgba(0,109,255,0.5)", c:"#132238", shadow:"0 0 16px rgba(0,109,255,0.4),0 4px 12px rgba(0,0,0,0.3)"},
    danger:  {bg:"rgba(239,68,68,0.1)",    b:"1px solid rgba(239,68,68,0.35)",   c:"#EF4444", shadow:"none"},
    amber:   {bg:"rgba(245,158,11,0.1)",   b:"1px solid rgba(245,158,11,0.35)",  c:"#F59E0B", shadow:"none"},
    admin:   {bg:"linear-gradient(135deg,#38BDF8,#006DFF)", b:"1px solid #38BDF8", c:"#132238",  shadow:"0 0 12px rgba(80,140,255,0.25)"},
    nhs:     {bg:"#005eb8",                b:"1px solid #005eb8",                c:"#132238",  shadow:"none"},
    green:   {bg:"rgba(34,197,94,0.12)",   b:"1px solid rgba(34,197,94,0.4)",    c:"#22C55E", shadow:"none"},
  };
  const st=variants[v]||variants.ghost;
  return <button onClick={onClick} disabled={disabled} style={{background:st.bg,border:st.b,color:st.c,padding:"6px 16px",borderRadius:14,fontSize:12,fontWeight:600,cursor:disabled?"not-allowed":"pointer",opacity:disabled?.4:1,display:"flex",alignItems:"center",justifyContent:"center",gap:6,whiteSpace:"nowrap",width:full?"100%":undefined,boxShadow:disabled?"none":st.shadow,transition:"all .18s",...sx}}>{children}</button>;
}

function Chip({children,color=C.muted,bg}){return <span style={{fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:14,background:bg||color+"1a",color,letterSpacing:".04em"}}>{children}</span>;}

function Row({label,value,mono}){return <div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderTop:"1px solid rgba(80,140,255,0.08)",fontSize:12}}><span style={{color:C.muted}}>{label}</span><span style={{fontWeight:500,fontFamily:mono?"monospace":"inherit"}}>{value}</span></div>;}

