// ROLE-BASED PERMISSION SYSTEM

// ══════════════════════════════════════════════════════════════════════════════

const ROLE_DEFAULTS={
  // Reception: appointment & front desk workflow — no clinical, no deep analytics
  reception: new Set(["dashboard","nba","huddle","calendar","waiting","patients","online_booking","receptionai","whatsapp","teamchat","recovery","shortnotice","accounts","finance","fp17","tasks","helpsupport"]),
  // Dentist: surgery & clinical — no business admin, no reception ops
  dentist:   new Set(["dashboard","nba","calendar","patients","notes","xray","fp17","uda","lab","teamchat","tasks","helpsupport","myreports"]),
  // Hygienist: clinical + recall — focused view
  hygienist: new Set(["dashboard","nba","calendar","patients","notes","teamchat","tasks","helpsupport","myreports"]),
  // Manager: full practice visibility
  manager:   new Set(["dashboard","nba","huddle","calendar","waiting","patients","online_booking","notes","xray","fp17","uda","teamchat","whatsapp","receptionai","comms","recovery","shortnotice","lab","accounts","payments","reports","finance","tasks","rota","myreports","manager","usermgmt","subscription","templates","audit","settings","helpsupport"]),
  superadmin: new Set([]),
};

// Per-user permission overrides (starts = role defaults, manager can add/remove)

const INIT_USER_PERMS=()=>Object.fromEntries(USERS.map(u=>([u.id,new Set(ROLE_DEFAULTS[u.role]||[])])));

// ── Core Permission Resolver ─────────────────────────────────────────────────
// Single source of truth. Hierarchy:
//   superadmin → global feature enabled → plan includes feature →
//   practice feature enabled → feature allowedRoles → userOverride → navPerm Set
function resolveAccess(userId,userRole,navId,userPerms,featureUserCfg,plan='Growth'){
  if(userRole==='superadmin')return true;
  const featureId=FEATURE_NAV_MAP[navId];
  if(featureId){
    const gCfg=GLOBAL_FEATURE_CONFIG.find(f=>f.id===featureId);
    const fCfg=(featureUserCfg||{})[featureId];
    if(gCfg&&!gCfg.enabled)return false;
    if(gCfg&&gCfg.price>0&&!gCfg.plans.includes(plan))return false;
    if(fCfg&&!fCfg.enabled)return false;
    if(fCfg){
      const ov=fCfg.userOverrides?.[userId];
      if(ov===false)return false;
      if(ov===true){/* explicit grant — still need nav perm below */}
      else if(fCfg.allowedRoles.length>0&&!fCfg.allowedRoles.includes(userRole))return false;
    }
  }
  const perms=userPerms instanceof Set?userPerms:new Set(userPerms||[]);
  return perms.has(navId);
}

