// MODERN SIDEBAR — role-aware, permission-filtered

// ══════════════════════════════════════════════════════════════════════════════

function Sidebar({page,setPage,user,onLogout,waiting,tasks,unread,userPerms,featureUserCfg,plan="Growth"}){

  const isAdmin=user?.role==="superadmin";

  const [wOpen,setWOpen]=useState(false); // waiting room widget expanded

  const rm=ROLE_META[user?.role]||ROLE_META.reception;

  const accent=isAdmin?C.adminAccent:rm.accent;

  const wl=waiting.filter(w=>w.status==="waiting").length;

  const ul=tasks.filter(t=>t.priority==="urgent"&&!t.done).length;

  const badges={waiting:wl,pending:0,unread,tasks:ul,rxai:0,recovery:0,nba:0,chat:0,tickets:7};

  // Build filtered nav from user permissions

  const myPerms=userPerms||ROLE_DEFAULTS[user?.role]||new Set();
  // resolveAccess applied per item for full hierarchy gating
  const canSee=(navId)=>resolveAccess(user?.id,user?.role,navId,myPerms,featureUserCfg,plan);

  const visibleItems=ALL_NAV_ITEMS.filter(item=>canSee(item.id));

  const groups=[...new Set(visibleItems.map(i=>i.g))];

  const adminGroups=[

    {g:"Overview",items:[{id:"admin_dash",l:"System Dashboard",Icon:BarChart2},{id:"admin_practices",l:"All Practices",Icon:Building2}]},

    {g:"Subscriptions",items:[{id:"admin_pricing",l:"Plan Builder",Icon:PoundSterling},{id:"admin_features",l:"Feature Management",Icon:Cpu},{id:"admin_seat_control",l:"Seat Control",Icon:Users2}]},

    {g:"Platform",items:[{id:"admin_ai",l:"Platform AI",Icon:Cpu},{id:"admin_data",l:"Data Manager",Icon:Database},{id:"admin_monitoring",l:"System Monitoring",Icon:Activity},{id:"admin_security",l:"Security & Compliance",Icon:Shield},{id:"admin_backup",l:"Cloud Backup",Icon:Server},{id:"admin_tx_plans",l:"Treatment Plans",Icon:Clipboard},{id:"admin_receptionai",l:"Reception AI",Icon:Phone},{id:"admin_updates",l:"Software Updates",Icon:Server}]},

    {g:"People",items:[{id:"admin_users",l:"Admin Users",Icon:Users2},{id:"admin_support_config",l:"Support Channels",Icon:Settings}]},

    {g:"Support",items:[{id:"admin_tickets",l:"Support Tickets",Icon:HelpCircle,badge:"tickets"},{id:"admin_support",l:"Support Access",Icon:Headphones},{id:"admin_integrations",l:"Integrations",Icon:Globe},{id:"admin_audit",l:"Activity Log",Icon:Shield},{id:"admin_appt_audit",l:"Appointment Audit",Icon:Activity}]},

  ];

  return(

    <div style={{width:220,flexShrink:0,background:"linear-gradient(180deg,#081632 0%,#071428 100%)",display:"flex",flexDirection:"column",height:"100%",overflow:"hidden",borderRight:"1px solid rgba(80,140,255,0.18)"}}>

      {/* Logo */}

      <div style={{padding:"16px 16px 12px",borderBottom:"1px solid rgba(80,140,255,0.15)",flexShrink:0,background:"rgba(8,22,50,0.8)"}}>

        <div style={{fontSize:16,fontWeight:800,color:"#F8FAFC",display:"flex",alignItems:"center",gap:8,marginBottom:2}}>

          <div style={{width:28,height:28,borderRadius:12,background:"linear-gradient(135deg,#006DFF,#8B5CF6)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,flexShrink:0}}>🦷</div>

          <span><span style={{color:"#F8FAFC",fontWeight:800}}>ProDental</span><span style={{color:"#3B82F6"}}>Connect</span></span>

        </div>

        <div style={{fontSize:9,color:"#CBD5E1",marginLeft:36}}>{getVersion()} · {isAdmin?"System Admin":user?.practice}</div>

      </div>

      {/* Practice isolation badge for non-admin users */}

      {!isAdmin&&<div style={{margin:"6px 10px 0",padding:"5px 8px",background:"rgba(0,109,255,0.08)",borderRadius:8,border:"1px solid rgba(56,189,248,0.15)",display:"flex",gap:6,alignItems:"center"}}>

        <span style={{fontSize:10,flexShrink:0}}>🔒</span>

        <div style={{minWidth:0}}>

          <div style={{fontSize:9,fontWeight:700,color:"#38BDF8",textTransform:"uppercase",letterSpacing:".06em"}}>Practice Scoped</div>

          <div style={{fontSize:9,color:"rgba(255,255,255,0.75)",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user?.practice}</div>

        </div>

      </div>}

      {!isAdmin&&<div style={{margin:"8px 10px 2px",padding:"7px 10px",background:"rgba(0,109,255,0.08)",borderRadius:10,border:"1px solid rgba(56,189,248,0.15)",display:"flex",gap:8,alignItems:"center"}}>

        <div style={{width:28,height:28,borderRadius:"50%",background:user?.color||rm.accent,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,color:"#132238",flexShrink:0}}>{user?.avatar}</div>

        <div style={{minWidth:0}}>

          <div style={{fontSize:11,fontWeight:700,color:"#132238",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user?.name?.split(" ").slice(-1)[0]||user?.name}</div>

          <div style={{fontSize:9,fontWeight:700,color:rm.accent,textTransform:"uppercase",letterSpacing:".08em"}}>{rm.label}</div>

        </div>

      </div>}

      {/* Nav */}

      <div style={{flex:1,overflowY:"auto",background:"#0F1C34",padding:"6px 0"}}>

        {isAdmin?adminGroups.map(grp=>(

          <div key={grp.g}>

            <div style={{padding:"12px 14px 3px",fontSize:8.5,fontWeight:800,color:"rgba(56,189,248,0.55)",textTransform:"uppercase",letterSpacing:".12em",borderTop:"1px solid rgba(80,140,255,0.06)",marginTop:4}}>{grp.g}</div>

            {grp.items.map(item=>{

              const active=page===item.id;const bdg=badges[item.badge];

              return <button key={item.id} onClick={()=>setPage(item.id)} style={{width:"100%",display:"flex",alignItems:"center",gap:9,padding:"7px 14px",border:"none",background:active?"linear-gradient(90deg,rgba(56,189,248,0.16),rgba(56,189,248,0.03))":"transparent",cursor:"pointer",borderLeft:`3px solid ${active?"#38BDF8":"transparent"}`,borderRadius:"0 10px 10px 0",margin:"1px 8px 1px 0",boxShadow:active?"inset 0 0 28px rgba(56,189,248,0.1),inset 0 0 0 1px rgba(80,140,255,0.06)":"none",transition:"all .1s"}}

                onMouseOver={e=>{if(!active)e.currentTarget.style.background="rgba(80,140,255,0.05)";}} onMouseOut={e=>{if(!active)e.currentTarget.style.background="transparent";}}>

                <item.Icon size={14} color={active?"#38BDF8":"rgba(148,163,184,0.6)"}/>

                <span style={{flex:1,fontSize:12,color:active?"#FFFFFF":"rgba(148,163,184,0.75)",fontWeight:active?700:400,textAlign:"left",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.l}</span>

                {bdg>0&&<span style={{fontSize:9,fontWeight:800,padding:"1px 6px",borderRadius:9,background:item.id==="admin_tickets"?"#EF4444":"#2563FF",boxShadow:item.id==="admin_tickets"?"0 0 6px rgba(239,68,68,0.4)":"none",color:"#132238"}}>{bdg}</span>}

              </button>;

            })}

          </div>

        )):groups.map(grp=>{

          const items=visibleItems.filter(i=>i.g===grp);

          return(

            <div key={grp}>

              <div style={{padding:"12px 14px 3px",fontSize:8.5,fontWeight:800,color:"rgba(56,189,248,0.55)",textTransform:"uppercase",letterSpacing:".12em",borderTop:"1px solid rgba(80,140,255,0.06)",marginTop:4}}>{grp}</div>

              {items.map(item=>{

                const active=page===item.id;const bdg=badges[item.badge];

                return <button key={item.id} onClick={()=>setPage(item.id)} style={{width:"100%",display:"flex",alignItems:"center",gap:9,padding:"7px 14px",border:"none",background:active?"linear-gradient(90deg,rgba(0,109,255,0.22),rgba(0,109,255,0.04))":"transparent",cursor:"pointer",borderLeft:`2px solid ${active?"#38BDF8":"transparent"}`,borderRadius:"0 10px 10px 0",margin:"1px 8px 1px 0",boxShadow:active?"inset 0 0 24px rgba(0,109,255,0.08),0 0 0 0.5px rgba(56,189,248,0.1)":"none",transition:"all .1s"}}

                  onMouseOver={e=>{if(!active)e.currentTarget.style.background="rgba(80,140,255,0.05)";}} onMouseOut={e=>{if(!active)e.currentTarget.style.background="transparent";}}>

                  <item.Icon size={14} color={active?"#60AEFF":"rgba(148,163,184,0.65)"}/>

                  <span style={{flex:1,fontSize:12,color:active?"#FFFFFF":"rgba(148,163,184,0.75)",fontWeight:active?700:400,textAlign:"left",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.l}</span>

                  {bdg>0&&<span style={{fontSize:9,fontWeight:800,padding:"1px 6px",borderRadius:9,background:item.badge==="recovery"||item.badge==="rxai"?"#EF4444":item.badge==="unread"?"#EF4444":"#2563FF",boxShadow:item.badge==="recovery"||item.badge==="unread"?"0 0 6px rgba(239,68,68,0.4)":"0 0 6px rgba(0,109,255,0.3)",color:"#132238"}}>{bdg}</span>}

                </button>;

              })}

              {/* Live waiting room widget — under Front Desk group */}

              {grp==="Front Desk"&&(["reception","manager","dentist","hygienist"].includes(user?.role))&&(()=>{

                const M=60000;

                const isDoc=["dentist","hygienist"].includes(user?.role);

                const myShort=user?.name?.replace("Dr. Sarah","Dr. S.").replace("Dr. Mike","Dr. M.")||"";

                // Dentists see only their queue; reception sees all

                const wNow=waiting.filter(w=>w.status==="waiting"&&(isDoc?(w.dentist===myShort||w.dentist===user?.name):true))

                  .sort((a,b)=>(a.in||0)-(b.in||0));

                const threshold=20;

                const longWait=wNow.some(w=>w.in&&(Date.now()-w.in)>threshold*M);

                if(!wNow.length)return null;

                const bc=longWait?"rgba(239,68,68,0.55)":"rgba(56,189,248,0.35)";

                const headerC=longWait?"#FCA5A5":"#38BDF8";

                return(

                  <div style={{margin:"3px 8px 8px",borderRadius:14,border:`1px solid ${longWait?"rgba(239,68,68,0.4)":"rgba(80,140,255,0.2)"}`,background:longWait?"rgba(239,68,68,0.08)":"rgba(0,109,255,0.08)",cursor:"pointer",padding:"7px 10px",display:"flex",gap:7,alignItems:"center"}}

                    onClick={()=>setPage("waiting")}>

                    <div style={{position:"relative",flexShrink:0}}>

                      <Users2 size={13} color={headerC}/>

                      {longWait&&<div style={{position:"absolute",top:-3,right:-3,width:6,height:6,borderRadius:"50%",background:"#EF4444",animation:"waitPulse 0.9s ease-in-out infinite"}}/>}

                    </div>

                    <span style={{flex:1,fontSize:10,fontWeight:700,color:headerC}}>In Waiting Room</span>

                    <span style={{fontSize:11,fontWeight:900,padding:"1px 8px",borderRadius:7,background:longWait?"#dc2626":"#2563FF",color:"#132238",fontFamily:"ui-monospace,monospace"}}>{wNow.length}</span>

                  </div>

                );

              })()}

            </div>

          );

        })}

      </div>

      {/* Footer */}

      <div style={{borderTop:"1px solid rgba(80,140,255,0.15)",padding:"8px 12px 0",flexShrink:0,background:"#071428"}}>
        <div style={{display:"flex",gap:5,marginBottom:5}}>
          <button
            onClick={()=>window.open("ReceptionKiosk.html","kiosk","width=768,height=1024,menubar=no,toolbar=no,location=no,status=no")}
            title="Open Reception iPad Check-In — separate app for the reception tablet"
            style={{flex:1,padding:"7px 0",border:"1px solid rgba(80,140,255,0.2)",borderRadius:8,background:"transparent",cursor:"pointer",fontSize:9,fontWeight:700,color:"#CBD5E1",fontFamily:"inherit",display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
            <span style={{fontSize:14}}>📱</span>
            <span>iPad Check-In</span>
          </button>
          <button
            onClick={()=>window.open("PatientPortal.html","portal","width=1024,height=768,menubar=no,toolbar=no,location=no,status=no")}
            title="Open Patient Portal — separate app for patients"
            style={{flex:1,padding:"7px 0",border:"1px solid rgba(80,140,255,0.2)",borderRadius:8,background:"transparent",cursor:"pointer",fontSize:9,fontWeight:700,color:"#CBD5E1",fontFamily:"inherit",display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
            <span style={{fontSize:14}}>🌐</span>
            <span>Patient Portal</span>
          </button>
        </div>
        <div style={{padding:"0 0 10px"}}>
        <button onClick={onLogout} style={{width:"100%",display:"flex",gap:8,alignItems:"center",padding:"7px 10px",border:"none",background:"rgba(80,140,255,0.04)",borderRadius:10,cursor:"pointer",color:"#94A3B8",fontSize:11}}>

          <LogOut size={13}/><span>Sign out</span>

        </button>
        </div>
      </div>

    </div>

  );

}

