    {user&&<div style={{marginBottom:14,padding:"12px 16px",background:"rgba(37,99,255,0.06)",border:"1px solid rgba(59,130,246,0.12)",borderRadius:12,display:"flex",gap:10,alignItems:"center"}}>
      <div style={{width:32,height:32,borderRadius:10,background:user.color||"#2563FF",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,color:"#132238",flexShrink:0}}>{user.avatar}</div>
      <div style={{flex:1}}>
        <div style={{fontSize:14,fontWeight:700,color:"#F8FAFC"}}>Good {new Date().getHours()<12?"morning":new Date().getHours()<17?"afternoon":"evening"}, {user.name?.split(" ").slice(-1)[0]}</div>
        <div style={{fontSize:11,color:"#CBD5E1"}}>{isDentistUser?"Surgery ready — "+wl+" patient"+(wl!==1?"s":"")+" in waiting room":isReceptionUser?"Front desk · "+wl+" waiting · Check daily priorities for actions":isManagerUser?"Practice overview · "+new Date().toLocaleDateString("en-GB",{weekday:"long",day:"numeric",month:"long"}):"Welcome"}</div>
      </div>
      {isDentistUser&&wl>0&&<div style={{padding:"4px 12px",background:"rgba(34,197,94,0.12)",border:"1px solid rgba(34,197,94,0.3)",borderRadius:8,fontSize:11,fontWeight:700,color:"#22C55E",flexShrink:0}}>{wl} waiting</div>}
    </div>}

