// DNA WORKFLOW ENGINE — Custom Hook
function WaitingPage({waiting,setWaiting,user,openPatient,setNotifs,waitThreshold,setWaitThreshold}){

  const {dnaWorkflows,dnaModal,setDnaModal,toastDNA,triggerDNAWorkflow}=useDNAWorkflow();
  const [markedDNA,setMarkedDNA]=useState([]); // list of {apt, markedAt} for undo
  const [recentDNA,setRecentDNA]=useState(null); // last marked (for undo toast)

  const M=60000;

  const threshold=waitThreshold||20; // minutes before turning red

  const [tick,setTick]=useState(0);

  const [manualName,setManualName]=useState("");

  const [manualDentist,setManualDentist]=useState("Dr. S. Patel");

  const [manualAppt,setManualAppt]=useState("");

  const [showAdd,setShowAdd]=useState(false);

  const [showThreshold,setShowThreshold]=useState(false);

  const [newThreshold,setNewThreshold]=useState(String(threshold));

  const [viewTab,setViewTab]=useState("waiting"); // waiting | daily

  const [toast,setToast]=useState(null);

  const doToast=m=>{setToast(m);setTimeout(()=>setToast(null),3000);};

  useEffect(()=>{const t=setInterval(()=>setTick(n=>n+1),10000);return()=>clearInterval(t);},[]);

  const isManager=user?.role==="manager";

  const isReception=user?.role==="reception"||user?.role==="manager";

  const isDentist=user?.role==="dentist"||user?.role==="hygienist";

  const wm=w=>w.in?Math.floor((Date.now()-w.in)/M):null;

  // Emoji face based on wait time vs threshold
  const waitFace=(mins)=>{
    if(mins===null)return"🗓";
    if(mins<=0)return"😊";
    if(mins<threshold*0.5)return"😊";
    if(mins<threshold*0.8)return"🙂";
    if(mins<threshold)return"😐";
    if(mins<threshold*1.5)return"😟";
    return"😰";
  };
  const waitFaceColor=(mins)=>{
    if(mins===null)return C.muted;
    if(mins<threshold*0.8)return C.green;
    if(mins<threshold)return C.amber;
    return C.red;
  };

  const waitingNow=waiting.filter(w=>w.status==="waiting").sort((a,b)=>(a.in||0)-(b.in||0));

  const bookedToday=waiting.filter(w=>w.status==="booked");

  const calledIn=waiting.filter(w=>w.status==="called");

  // Today's full schedule from INIT_APPTS — synced with calendar

  const dailyList=[

    {id:"D1",time:"08:30",name:"John Mills",     pid:"P1",dentist:"Dr. S. Patel",type:"Check-up & Composite",  status:waiting.find(x=>x.name==="John Mills")?.status||"scheduled"},

    {id:"D2",time:"09:00",name:"Tom Bright",     pid:null,dentist:"Dr. S. Patel",type:"Extraction LL7",          status:waiting.find(x=>x.name==="Tom Bright")?.status||"scheduled"},

    {id:"D3",time:"09:30",name:"Sarah Chen",     pid:"P2",dentist:"Dr. S. Patel",type:"Crown Fit UR6",           status:waiting.find(x=>x.name==="Sarah Chen")?.status||"waiting"},

    {id:"D4",time:"10:00",name:"Carol Nash",     pid:null,dentist:"Dr. S. Patel",type:"New Patient Exam",        status:waiting.find(x=>x.name==="Carol Nash")?.status||"scheduled"},

    {id:"D5",time:"10:30",name:"Amy Torres",     pid:"P4",dentist:"Dr. M. Chen", type:"Implant Consultation",    status:waiting.find(x=>x.name==="Amy Torres")?.status||"booked"},

    {id:"D6",time:"11:30",name:"David Park",     pid:"P5",dentist:"Dr. M. Chen", type:"OPG Review",               status:waiting.find(x=>x.name==="David Park")?.status||"booked"},

    {id:"D7",time:"13:00",name:"Robert Hall",    pid:"P3",dentist:"Dr. M. Chen", type:"RCT Session 3 LL7",        status:waiting.find(x=>x.name==="Robert Hall")?.status||"booked"},

    {id:"D8",time:"14:00",name:"Lisa White",     pid:"P6",dentist:"Dr. S. Patel",type:"Composite Smile Makeover", status:waiting.find(x=>x.name==="Lisa White")?.status||"booked"},

    {id:"D9",time:"14:00",name:"Amy Grant (H)",  pid:null,dentist:"Amy Grant",   type:"Scale & Polish NHS",       status:"scheduled"},

    {id:"D10",time:"16:00",name:"Sarah Chen",    pid:"P2",dentist:"Amy Grant",   type:"Hygiene Review",           status:"scheduled"},

  ];

  const checkInFromDaily=(apt)=>{

    // If already in waiting list update, else add new entry

    const exists=waiting.find(x=>x.name===apt.name&&x.appt===apt.time);

    if(exists){

      setWaiting(p=>p.map(x=>x.id===exists.id?{...x,in:Date.now(),status:"waiting"}:x));

    } else {

      setWaiting(p=>[...p,{id:"W"+Date.now(),name:apt.name,pid:apt.pid,appt:apt.time,dentist:apt.dentist,in:Date.now(),status:"waiting"}]);

    }

    // Notify dentist

    if(setNotifs){

      const now=new Date().toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"});

      setNotifs(p=>[{id:"CK"+Date.now(),type:"checkin",title:"Patient arrived — "+apt.name,desc:apt.name+" checked in for "+apt.time+" · "+apt.dentist,at:now,read:false},...p]);

    }

    doToast("✓ "+apt.name+" checked in · "+apt.dentist+" notified");

  };

  const addManual=()=>{

    if(!manualName.trim())return;

    const entry={id:"W"+Date.now(),name:manualName.trim(),pid:null,appt:manualAppt||"Walk-in",dentist:manualDentist,in:Date.now(),status:"waiting"};

    setWaiting(p=>[...p,entry]);

    if(setNotifs){

      const now=new Date().toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"});

      setNotifs(p=>[{id:"CK"+Date.now(),type:"checkin",title:"Walk-in arrived — "+manualName,desc:manualName+" (walk-in) · "+manualDentist,at:now,read:false},...p]);

    }

    doToast("✓ "+manualName+" added to waiting room · "+manualDentist+" notified");

    setManualName("");setManualAppt("");setShowAdd(false);

  };

  const callInPatient=(w)=>{
    // Move patient from "waiting" → "called/in surgery"
    setWaiting(p=>p.map(x=>x.id===w.id?{...x,status:"called",calledAt:Date.now()}:x));

    // Play audio chime notification
    try {
      const ctx=new (window.AudioContext||window.webkitAudioContext)();
      const playNote=(freq,start,dur,vol=0.3)=>{
        const osc=ctx.createOscillator(); const gain=ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.value=freq; osc.type="sine";
        gain.gain.setValueAtTime(vol,ctx.currentTime+start);
        gain.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+start+dur);
        osc.start(ctx.currentTime+start); osc.stop(ctx.currentTime+start+dur);
      };
      playNote(523,0,.3); playNote(659,.2,.3); playNote(784,.4,.5);
    } catch(e){}

    // Notify reception
    if(setNotifs){
      const now=new Date().toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"});
      setNotifs(p=>[{id:"CI"+Date.now(),type:"callin",title:"Please send patient in — "+w.name,desc:user?.name+" is ready for "+w.name+" · Please ask them to go to surgery",at:now,read:false},...p]);
    }

    doToast("🔔 Reception notified — please send "+w.name+" in");

  };

  const removePatient=(id)=>setWaiting(p=>p.filter(x=>x.id!==id));

  const DENTISTS=["Dr. S. Patel","Dr. M. Chen","Amy Grant"];

  const statusMeta={

    scheduled:{bg:"#132238",border:"rgba(80,140,255,0.2)",badge:"rgba(80,140,255,0.2)",bc:"#64748b",l:"Scheduled"},

    booked:    {bg:"rgba(80,140,255,0.06)",border:"#99f6e4",badge:C.teal+"22",bc:C.teal,l:"Due In"},

    waiting:   {bg:"#132238",   border:"rgba(80,140,255,0.2)", badge:"rgba(99,102,241,0.08)",bc:C.amber,l:"Waiting"},

    called:    {bg:"rgba(34,197,94,0.08)",border:"#bbf7d0",badge:"#dcfce7", bc:C.green,l:"Called In"},

    completed: {bg:"#132238",border:"rgba(80,140,255,0.2)", badge:"rgba(80,140,255,0.1)",bc:"#64748b",l:"Done"},

  };

  return(

    <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>

      {toast&&<div style={{position:"fixed",top:64,right:18,padding:"10px 18px",background:"linear-gradient(135deg,#006DFF,#0057CC)",color:"#132238",boxShadow:"0 0 14px rgba(0,109,255,0.4)",borderRadius:14,fontSize:12,fontWeight:600,zIndex:600,boxShadow:"0 4px 20px rgba(0,0,0,.2)",display:"flex",gap:7,alignItems:"center"}}><Check size={13}/>{toast}</div>}
      {recentDNA&&<div style={{position:"fixed",top:72,right:18,zIndex:620,background:"#0F1C34",border:"1.5px solid rgba(239,68,68,0.45)",borderRadius:14,padding:"12px 16px",display:"flex",gap:12,alignItems:"center",boxShadow:"0 4px 20px rgba(0,0,0,0.4)",minWidth:300}}>
        <div style={{flex:1}}>
          <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC"}}>🚫 {recentDNA.apt.name} — marked DNA</div>
          <div style={{fontSize:10,color:"#CBD5E1",marginTop:2}}>Tap to undo if this was a mistake</div>
        </div>
        <button onClick={()=>{setWaiting(p=>[...p,{...recentDNA.apt,status:"waiting",in:Date.now()}]);setRecentDNA(null);}} style={{padding:"7px 14px",background:"linear-gradient(135deg,#2563FF,#1D4ED8)",border:"none",borderRadius:9,cursor:"pointer",fontSize:11,fontWeight:800,color:"#fff",fontFamily:"inherit",whiteSpace:"nowrap"}}>↩ Undo</button>
        <button onClick={()=>setRecentDNA(null)} style={{border:"none",background:"transparent",cursor:"pointer",color:"#94A3B8",fontSize:18,padding:0}}>✕</button>
      </div>}


      {/* Header */}

      <div style={{background:"#132238",borderBottom:"1px solid rgba(56,189,248,0.07)",padding:"12px 18px",flexShrink:0}}>

        <div style={{display:"flex",gap:12,alignItems:"center",marginBottom:12}}>

          <div style={{width:38,height:38,borderRadius:14,background:"linear-gradient(135deg,#006DFF,#38BDF8)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>🚪</div>

          <div style={{flex:1}}>

            <div style={{fontSize:15,fontWeight:800}}>Waiting Room</div>

            <div style={{fontSize:11,color:"#CBD5E1"}}>

              {waitingNow.length} waiting · {bookedToday.length} expected · threshold: <strong style={{color:waitingNow.some(w=>(wm(w)||0)>=threshold)?C.red:C.teal}}>{threshold} min</strong>

            </div>

          </div>

          <div style={{display:"flex",gap:6,alignItems:"center"}}>

            {/* Stat pills */}

            {[

              {l:"Waiting",v:waitingNow.length,c:waitingNow.some(w=>(wm(w)||0)>=threshold)?C.red:C.amber,bg:waitingNow.some(w=>(wm(w)||0)>=threshold)?"#fee2e2":"rgba(99,102,241,0.08)"},

              {l:"Expected",v:bookedToday.length,c:C.teal,bg:C.tealL},

              {l:"Called In",v:calledIn.length,c:C.green,bg:"#dcfce7"},

            ].map(s=>(

              <div key={s.l} style={{padding:"5px 12px",background:s.bg,borderRadius:12,textAlign:"center",minWidth:60}}>

                <div style={{fontSize:17,fontWeight:900,color:s.c,fontFamily:"ui-monospace,monospace"}}>{s.v}</div>

                <div style={{fontSize:9,color:s.c,opacity:.7,fontWeight:700}}>{s.l}</div>

              </div>

            ))}

            {isReception&&<button onClick={()=>setShowAdd(v=>!v)} style={{padding:"7px 14px",background:"linear-gradient(135deg,#006DFF,#0057CC)",color:"#132238",boxShadow:"0 0 14px rgba(0,109,255,0.4)",border:"none",borderRadius:9,cursor:"pointer",fontSize:12,fontWeight:700,display:"flex",gap:5,alignItems:"center"}}><Plus size={13}/>Check In</button>}

            {isManager&&<button onClick={()=>setShowThreshold(v=>!v)} style={{padding:"7px 12px",border:`1.5px solid rgba(59,130,246,0.35)`,borderRadius:9,background:"#0F1C34",cursor:"pointer",fontSize:11,color:"#CBD5E1",fontWeight:600}}>⏱ Threshold</button>}

          </div>

        </div>

        {/* Manual check-in form */}

        {showAdd&&<div style={{padding:"12px 14px",background:"rgba(80,140,255,0.06)",border:`1px solid ${C.teal}40`,borderRadius:14,marginBottom:8,display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>

          <input value={manualName} onChange={e=>setManualName(e.target.value)} placeholder="Patient name" style={{padding:"7px 10px",border:"1px solid rgba(56,189,248,0.12)",borderRadius:14,fontSize:12,fontFamily:"inherit",outline:"none",flex:1,minWidth:140}}/>

          <input value={manualAppt} onChange={e=>setManualAppt(e.target.value)} placeholder="Appt time (optional)" style={{padding:"7px 10px",border:"1px solid rgba(56,189,248,0.12)",borderRadius:14,fontSize:12,fontFamily:"inherit",outline:"none",width:120}}/>

          <select value={manualDentist} onChange={e=>setManualDentist(e.target.value)} style={{padding:"7px 10px",border:"1px solid rgba(56,189,248,0.12)",borderRadius:14,fontSize:12,fontFamily:"inherit",outline:"none"}}>

            {DENTISTS.map(d=><option key={d}>{d}</option>)}

          </select>

          <button onClick={addManual} style={{padding:"7px 16px",background:"linear-gradient(135deg,#006DFF,#0057CC)",color:"#132238",boxShadow:"0 0 14px rgba(0,109,255,0.4)",border:"none",borderRadius:12,cursor:"pointer",fontSize:12,fontWeight:700}}>✓ Add</button>

          <button onClick={()=>setShowAdd(false)} style={{padding:"7px 12px",border:"1px solid rgba(56,189,248,0.12)",borderRadius:14,background:"#132238",cursor:"pointer",fontSize:11,color:"#CBD5E1"}}>Cancel</button>

        </div>}

        {/* Manager threshold setting */}

        {showThreshold&&isManager&&<div style={{padding:"10px 14px",background:"rgba(15,23,42,0.7)",border:"1px solid rgba(245,158,11,0.2)",borderRadius:14,marginBottom:8,display:"flex",gap:8,alignItems:"center"}}>

          <span style={{fontSize:12,fontWeight:600}}>⏱ Alert after</span>

          <input type="number" min="5" max="60" value={newThreshold} onChange={e=>setNewThreshold(e.target.value)} style={{width:60,padding:"5px 8px",border:`1.5px solid rgba(59,130,246,0.35)`,borderRadius:7,fontSize:13,fontFamily:"ui-monospace,monospace",outline:"none",textAlign:"center"}}/>

          <span style={{fontSize:12,color:"#CBD5E1"}}>minutes waiting</span>

          <button onClick={()=>{setWaitThreshold&&setWaitThreshold(parseInt(newThreshold)||20);setShowThreshold(false);doToast("Wait threshold set to "+newThreshold+" minutes");}} style={{padding:"6px 14px",background:C.amber,color:"#132238",border:"none",borderRadius:7,cursor:"pointer",fontSize:12,fontWeight:700}}>Save</button>

          <button onClick={()=>setShowThreshold(false)} style={{padding:"6px 10px",border:`1.5px solid rgba(59,130,246,0.35)`,borderRadius:7,background:"#132238",cursor:"pointer",fontSize:11,color:"#CBD5E1"}}>Cancel</button>

        </div>}

        {/* View tabs */}

        <div style={{display:"flex",gap:0}}>

          {[{id:"waiting",l:"🚶 Waiting Now"},{id:"daily",l:"📅 Daily Schedule"}].map(t=>(

            <button key={t.id} onClick={()=>setViewTab(t.id)} style={{padding:"6px 16px",border:"none",borderBottom:`2px solid ${viewTab===t.id?C.teal:"transparent"}`,background:"transparent",cursor:"pointer",fontSize:12,fontWeight:viewTab===t.id?700:400,color:viewTab===t.id?C.teal:C.muted,marginBottom:-1}}>

              {t.l}

            </button>

          ))}

        </div>

      </div>

      {/* ── WAITING NOW TAB ── */}

      {viewTab==="waiting"&&<div style={{flex:1,overflowY:"auto",background:"#0F1C34",padding:20,backgroundImage:"radial-gradient(ellipse at 30% 0%,rgba(0,109,255,0.06) 0%,transparent 50%)"}}>

        {waitingNow.length===0&&calledIn.length===0&&<div style={{textAlign:"center",padding:"40px",background:"rgba(0,109,255,0.06)",borderRadius:16,border:"1px solid rgba(80,140,255,0.18)"}}>

          <div style={{fontSize:36,marginBottom:10}}>✅</div>

          <div style={{fontSize:15,fontWeight:700,color:C.green}}>No patients waiting right now</div>

          <div style={{fontSize:12,color:"#CBD5E1",marginTop:4}}>Use Daily Schedule to check in today's appointments</div>

        </div>}

        {calledIn.length>0&&<>

          <div style={{fontSize:10,fontWeight:800,color:"#22C55E",textTransform:"uppercase",letterSpacing:".08em",marginBottom:8,display:"flex",alignItems:"center",gap:6}}><div style={{width:7,height:7,borderRadius:"50%",background:"#22C55E",boxShadow:"0 0 6px rgba(34,197,94,0.6)"}}/>In Surgery</div>

          {calledIn.map(w=>(
            <div key={w.id} style={{background:"rgba(34,197,94,0.07)",border:"1px solid rgba(34,197,94,0.25)",borderLeft:"3px solid #22C55E",borderRadius:16,padding:"12px 16px",marginBottom:8,display:"flex",gap:12,alignItems:"center"}}>
              {/* Green avatar with pulsing dot */}
              <div style={{width:42,height:42,borderRadius:12,background:"rgba(34,197,94,0.12)",border:"1.5px solid rgba(34,197,94,0.35)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:800,color:"#4ADE80",flexShrink:0,position:"relative"}}>
                {w.name.split(" ").map(n=>n[0]).join("").slice(0,2)}
                <div style={{position:"absolute",top:-3,right:-3,width:10,height:10,borderRadius:"50%",background:"#22C55E",border:"2px solid #061826",animation:"glowPulse 2s ease-in-out infinite"}}/>
              </div>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:800,letterSpacing:"-.01em",color:"#4ADE80"}}>{w.name}</div>
                <div style={{fontSize:11,color:"#CBD5E1",marginBottom:2}}>{w.appt} · {w.dentist}</div>
                <div style={{display:"flex",alignItems:"center",gap:5}}>
                  <div style={{width:6,height:6,borderRadius:"50%",background:"#22C55E"}}/>
                  <span style={{fontSize:10,color:"#22C55E",fontWeight:700}}>In Surgery</span>
                </div>
              </div>
              {/* Dentist: open record */}
              {w.pid&&isDentist&&<button onClick={()=>openPatient&&openPatient(w.pid,"charting")} style={{padding:"7px 12px",background:"linear-gradient(135deg,#006DFF,#1D4ED8)",color:"#fff",boxShadow:"0 0 12px rgba(0,109,255,0.3)",border:"none",borderRadius:10,cursor:"pointer",fontSize:11,fontWeight:700,whiteSpace:"nowrap"}}>🦷 Open Record</button>}
              {/* Mark complete */}
              <button onClick={()=>{removePatient(w.id);doToast("✓ "+w.name+" — appointment complete");}} style={{padding:"7px 12px",border:"1px solid rgba(34,197,94,0.3)",borderRadius:10,background:"rgba(34,197,94,0.08)",cursor:"pointer",fontSize:11,fontWeight:700,color:"#22C55E",whiteSpace:"nowrap",display:"flex",gap:4,alignItems:"center"}}><Check size={11}/>Done</button>
            </div>
          ))}
                    <div style={{height:1,background:C.border,margin:"12px 0"}}/>

        </>}

        {waitingNow.length>0&&<>

          <div style={{fontSize:10,fontWeight:800,color:"#F59E0B",textTransform:"uppercase",letterSpacing:".08em",marginBottom:8,display:"flex",alignItems:"center",gap:6}}><div style={{width:7,height:7,borderRadius:"50%",background:"#F59E0B",boxShadow:"0 0 6px rgba(245,158,11,0.5)"}}/>Waiting · {waitingNow.length} patient{waitingNow.length!==1?"s":""}</div>

          {waitingNow.map(w=>{

            const mins=wm(w);

            const overdue=mins!==null&&mins>=threshold;

            const warn=mins!==null&&mins>=Math.floor(threshold*0.7)&&!overdue;

            const bc=overdue?C.red:warn?C.amber:C.teal;

            const bg=overdue?"rgba(239,68,68,0.07)":warn?"rgba(245,158,11,0.06)":"rgba(15,23,42,0.8)";
            const cardBorder=overdue?"rgba(239,68,68,0.3)":warn?"rgba(245,158,11,0.25)":"rgba(80,140,255,0.22)";

            const pt=PATIENTS.find(p=>p.id===w.pid);

            return(

              <div key={w.id} style={{background:bg,border:`1px solid ${cardBorder}`,borderLeft:`3px solid ${bc}`,borderRadius:16,padding:"14px 16px",marginBottom:10,boxShadow:"0 4px 20px rgba(0,0,0,0.25)",animation:overdue?"waitPulse 2s ease-in-out infinite,glowPulse 2s ease-in-out infinite":"none"}}>

                <div style={{display:"flex",gap:12,alignItems:"center"}}>

                  {/* Emoji face based on wait time */}
                  <div style={{width:44,height:44,borderRadius:14,background:bc+"22",border:`2px solid ${bc}`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",flexShrink:0,fontSize:20,lineHeight:1}}>
                    <span>{waitFace(mins)}</span>
                    <span style={{fontSize:8,fontWeight:800,color:waitFaceColor(mins),fontFamily:"ui-monospace,monospace",marginTop:1}}>{mins!==null?mins+"m":""}</span>
                  </div>

                  <div style={{flex:1,minWidth:0}}>

                    <div style={{display:"flex",gap:7,alignItems:"center",marginBottom:2}}>

                      <span style={{fontSize:13,fontWeight:800,letterSpacing:"-.01em"}}>{w.name}</span>

                      {overdue&&<span style={{fontSize:10,fontWeight:800,padding:"1px 7px",borderRadius:8,background:"rgba(239,68,68,0.12)",color:C.red,}}>⚠️ OVERDUE</span>}

                    </div>

                    <div style={{fontSize:11,color:"#CBD5E1"}}>{w.appt} · {w.dentist}</div>

                    {pt?.medAlerts?.length>0&&<div style={{fontSize:10,color:C.red,fontWeight:600,marginTop:2}}>⚠ {pt.medAlerts[0]}</div>}

                  </div>

                  {/* Wait time */}
                  <div style={{textAlign:"center",flexShrink:0,minWidth:52}}>
                    <div style={{fontSize:20,fontWeight:900,color:bc,fontFamily:"ui-monospace,monospace",lineHeight:1}}>{mins!==null?mins:"-"}</div>
                    <div style={{fontSize:10,color:"#CBD5E1",marginTop:1,fontWeight:500}}>min wait</div>
                    {mins!==null&&mins>=threshold&&<div style={{fontSize:10,fontWeight:800,color:"#FCA5A5",marginTop:2}}>OVER LIMIT</div>}
                  </div>

                  {/* Actions — role specific */}
                  <div style={{display:"flex",flexDirection:"column",gap:6,flexShrink:0,minWidth:110}}>
                    {/* DENTIST: Call In button — removes from waiting, opens record */}
                    {isDentist&&(
                      <button onClick={()=>{
                        callInPatient(w);
                        doToast("🔔 "+w.name+" called in — reception notified");
                      }} style={{padding:"7px 12px",background:"linear-gradient(135deg,#006DFF,#1D4ED8)",color:"#fff",boxShadow:"0 0 16px rgba(0,109,255,0.4)",border:"none",borderRadius:10,cursor:"pointer",fontSize:11,fontWeight:700,whiteSpace:"nowrap",display:"flex",gap:5,alignItems:"center",justifyContent:"center"}}>
                        <UserCheck size={12}/>Call In
                      </button>
                    )}
                    {/* DENTIST: Open patient record */}
                    {isDentist&&w.pid&&(
                      <button onClick={()=>openPatient&&openPatient(w.pid,"charting")} style={{padding:"7px 12px",border:"1px solid rgba(80,140,255,0.25)",borderRadius:10,background:"rgba(0,109,255,0.1)",cursor:"pointer",fontSize:11,fontWeight:700,color:"#38BDF8",whiteSpace:"nowrap",display:"flex",gap:5,alignItems:"center",justifyContent:"center"}}>
                        🦷 Record
                      </button>
                    )}
                    {/* RECEPTION: Cancel/remove patient */}
                    {isReception&&(
                      <button onClick={()=>{
                        removePatient(w.id);
                        doToast("✓ "+w.name+" removed from waiting room");
                      }} style={{padding:"7px 12px",border:"1px solid rgba(239,68,68,0.3)",borderRadius:10,background:"rgba(239,68,68,0.08)",cursor:"pointer",fontSize:11,fontWeight:700,color:"#FCA5A5",whiteSpace:"nowrap",display:"flex",gap:5,alignItems:"center",justifyContent:"center"}}>
                        <UserX size={11}/>Cancel
                      </button>
                    )}
                  </div>

                </div>

                {/* Wait bar */}

                {mins!==null&&<div style={{marginTop:8,height:5,background:"rgba(80,140,255,0.1)",borderRadius:3,overflow:"hidden"}}>

                  <div style={{height:"100%",width:Math.min(100,mins/threshold*100)+"%",background:bc,borderRadius:3,transition:"width .5s"}}/>

                </div>}

              </div>

            );

          })}

        </>}

      </div>}

      {/* ── DAILY SCHEDULE TAB ── */}

      {viewTab==="daily"&&<div style={{flex:1,overflowY:"auto",background:"#0F1C34",padding:20,backgroundImage:"radial-gradient(ellipse at 30% 0%,rgba(0,109,255,0.06) 0%,transparent 50%)"}}>

        <div style={{fontSize:11,color:"#CBD5E1",marginBottom:12}}>Today's appointments · Click <strong>Check In</strong> when patient arrives · Synced with calendar</div>

        <div style={{background:"#0F1C34",borderRadius:16,overflow:"hidden",boxShadow:"0 2px 16px rgba(0,0,0,0.2),0 0 0 1px rgba(80,140,255,0.06)",border:"1px solid rgba(80,140,255,0.16)",boxShadow:"0 4px 24px rgba(0,109,255,0.08)"}}>

          {/* Column headers */}

          <div style={{display:"grid",gridTemplateColumns:"70px 1fr 130px 110px 110px",padding:"8px 14px",background:"#0F1C34",borderBottom:"1px solid rgba(56,189,248,0.07)",fontSize:10,fontWeight:800,color:"#CBD5E1",textTransform:"uppercase",letterSpacing:".06em"}}>

            <span>Time</span><span>Patient</span><span>Dentist</span><span>Treatment</span><span>Action</span>

          </div>

          {dailyList.map((apt,i)=>{

            const wEntry=waiting.find(x=>x.name===apt.name);

            const inWaiting=wEntry?.status==="waiting";

            const isCalled=wEntry?.status==="called";

            const isDone=wEntry?.status==="completed"||apt.status==="completed";

            const mins=inWaiting&&wEntry?.in?Math.floor((Date.now()-wEntry.in)/M):null;

            const overdue=mins!==null&&mins>=threshold;

            const rowBg=isCalled?"rgba(34,197,94,0.08)":inWaiting&&overdue?"rgba(239,68,68,0.08)":inWaiting?"rgba(99,102,241,0.08)":"#132238";

            return(

              <div key={apt.id} style={{display:"grid",gridTemplateColumns:"70px 1fr 130px 110px 110px",padding:"10px 14px",borderTop:i>0?`1px solid rgba(56,189,248,0.07)`:"none",alignItems:"center",background:"transparent"}}>

                <span style={{fontSize:12,fontWeight:700,fontFamily:"ui-monospace,monospace",color:"#38BDF8"}}>{apt.time}</span>

                <div>

                  <div style={{fontSize:12,fontWeight:600}}>{apt.name}</div>

                  {inWaiting&&overdue&&<span style={{fontSize:9,fontWeight:800,padding:"1px 5px",borderRadius:4,background:"rgba(239,68,68,0.12)",color:C.red}}>⚠️ {mins}m waiting</span>}

                  {inWaiting&&!overdue&&mins!==null&&<span style={{fontSize:9,color:C.amber}}>Waiting {mins}m</span>}

                  {isCalled&&<span style={{fontSize:9,fontWeight:700,color:C.green}}>✓ Called in</span>}

                </div>

                <span style={{fontSize:11,color:"#CBD5E1"}}>{apt.dentist}</span>

                <span style={{fontSize:10,color:"#CBD5E1",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{apt.type}</span>

                <div style={{display:"flex",flexDirection:"column",gap:5,alignItems:"flex-end",flexShrink:0,minWidth:100}}>

                  {/* RECEPTION: Check In + Mark DNA side by side */}
                  {!inWaiting&&!isCalled&&!isDone&&isReception&&(<>
                    <button onClick={()=>checkInFromDaily(apt)} style={{padding:"6px 14px",background:"linear-gradient(135deg,#006DFF,#1D4ED8)",color:"#fff",boxShadow:"0 0 14px rgba(0,109,255,0.4)",border:"none",borderRadius:8,cursor:"pointer",fontSize:11,fontWeight:700,display:"flex",gap:5,alignItems:"center",width:"100%",justifyContent:"center"}}>
                      <UserCheck size={11}/>Check In
                    </button>
                    <button onClick={()=>{
                        triggerDNAWorkflow({patient:apt.name,pid:apt.pid,type:apt.type||apt.treatment,dentist:apt.dentist,time:apt.time,phone:apt.phone||"07700 900000",value:apt.value||null});
                        const entry={apt:{...apt},markedAt:Date.now()};
                        setMarkedDNA(p=>[entry,...p]);
                        setRecentDNA(entry);
                        setTimeout(()=>setRecentDNA(null),8000);
                      }}
                      style={{padding:"5px 11px",border:"1px solid rgba(239,68,68,0.3)",borderRadius:8,background:"rgba(239,68,68,0.08)",cursor:"pointer",fontSize:10,fontWeight:700,color:"#EF4444",display:"flex",gap:4,alignItems:"center",width:"100%",justifyContent:"center"}}>
                      🚫 Mark DNA
                    </button>
                  </>)}

                  {/* DENTIST: Call In when patient waiting */}
                  {inWaiting&&isDentist&&(
                    <button onClick={()=>{wEntry&&callInPatient(wEntry);doToast("🔔 "+apt.name+" called in");}} style={{padding:"6px 14px",background:"linear-gradient(135deg,#22C55E,#16A34A)",color:"#132238",boxShadow:"0 0 12px rgba(34,197,94,0.35)",border:"none",borderRadius:8,cursor:"pointer",fontSize:11,fontWeight:700,display:"flex",gap:5,alignItems:"center",width:"100%",justifyContent:"center"}}>
                      <UserCheck size={11}/>Call In
                    </button>
                  )}

                  {/* Status chips */}
                  {inWaiting&&isReception&&<span style={{fontSize:10,fontWeight:600,padding:"3px 9px",borderRadius:7,background:"rgba(245,158,11,0.06)",color:C.amber,textAlign:"center",width:"100%"}}>Waiting {mins}m</span>}
                  {isCalled&&<span style={{fontSize:10,fontWeight:600,padding:"3px 9px",borderRadius:7,background:"rgba(0,109,255,0.1)",color:C.green,textAlign:"center",width:"100%"}}>✓ In Surgery</span>}
                  {isDone&&<span style={{fontSize:10,color:"#CBD5E1",textAlign:"center",width:"100%"}}>Done</span>}

                </div>

              </div>

            );

          })}

        </div>

        {/* DNA Workflows Panel */}
        {/* Marked DNA — Re-add or Check In */}
      {markedDNA.length>0&&<div style={{borderTop:"1px solid rgba(239,68,68,0.2)",background:"rgba(239,68,68,0.04)"}}>
        <div style={{padding:"8px 16px 6px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{display:"flex",gap:6,alignItems:"center",fontSize:10,fontWeight:800,color:"rgba(239,68,68,0.9)",textTransform:"uppercase",letterSpacing:".07em"}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:"#EF4444"}}/>
            DNA — {markedDNA.length} missed · <span style={{color:"#CBD5E1",fontWeight:400,textTransform:"none",letterSpacing:0}}>Re-add if marked by mistake</span>
          </div>
        </div>
        {markedDNA.map((entry,i)=>(
          <div key={entry.markedAt} style={{display:"flex",gap:12,alignItems:"center",padding:"9px 16px",borderTop:"1px solid rgba(239,68,68,0.08)"}}>
            <div style={{flex:1}}>
              <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC"}}>{entry.apt.name}</div>
              <div style={{fontSize:10,color:"#94A3B8"}}>{entry.apt.time} · {entry.apt.dentist} · {entry.apt.treatment||entry.apt.type}</div>
            </div>
            <div style={{display:"flex",gap:5,flexShrink:0}}>
              <button onClick={()=>{setWaiting(p=>[...p,{...entry.apt,status:"waiting",in:Date.now()}]);setMarkedDNA(p=>p.filter(x=>x.markedAt!==entry.markedAt));}} style={{padding:"5px 11px",background:"rgba(59,130,246,0.1)",border:"1px solid rgba(80,140,255,0.28)",borderRadius:7,cursor:"pointer",fontSize:10,fontWeight:700,color:"#60A5FA",fontFamily:"inherit",whiteSpace:"nowrap"}}>↩ Re-add</button>
              <button onClick={()=>{setWaiting(p=>[...p,{...entry.apt,status:"called",in:Date.now()}]);setMarkedDNA(p=>p.filter(x=>x.markedAt!==entry.markedAt));}} style={{padding:"5px 11px",background:"rgba(34,197,94,0.1)",border:"1px solid rgba(34,197,94,0.28)",borderRadius:7,cursor:"pointer",fontSize:10,fontWeight:700,color:"#4ADE80",fontFamily:"inherit",whiteSpace:"nowrap"}}>✓ Check In</button>
              <button onClick={()=>setMarkedDNA(p=>p.filter(x=>x.markedAt!==entry.markedAt))} style={{padding:"5px 8px",border:"1px solid rgba(239,68,68,0.2)",borderRadius:7,background:"transparent",cursor:"pointer",fontSize:10,color:"#EF4444",fontFamily:"inherit"}}>✕</button>
            </div>
          </div>
        ))}
      </div>}
      {dnaWorkflows.length>0&&<div style={{padding:"14px 18px",borderTop:"1px solid rgba(80,140,255,0.08)"}}>
          <div style={{fontSize:10,fontWeight:800,color:"rgba(239,68,68,0.7)",textTransform:"uppercase",letterSpacing:".1em",marginBottom:10,display:"flex",alignItems:"center",gap:7}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:"#EF4444"}}/>
            DNA Workflows Active · {dnaWorkflows.length} patient{dnaWorkflows.length!==1?"s":""}
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:7}}>
            {dnaWorkflows.map(w=>(
              <div key={w.id} onClick={()=>setDnaModal(w)} style={{display:"flex",gap:12,padding:"10px 13px",background:"rgba(239,68,68,0.05)",border:"1px solid rgba(239,68,68,0.2)",borderRadius:12,cursor:"pointer",alignItems:"center",transition:"all .15s"}}
                onMouseOver={e=>e.currentTarget.style.background="rgba(239,68,68,0.09)"} onMouseOut={e=>e.currentTarget.style.background="rgba(239,68,68,0.05)"}>
                <span style={{fontSize:18,flexShrink:0}}>🚫</span>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC"}}>{w.patient}</div>
                  <div style={{fontSize:10,color:"#CBD5E1"}}>{w.apptType} · {w.time} · {w.dentist}</div>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:3,alignItems:"flex-end",flexShrink:0}}>
                  <div style={{display:"flex",gap:4}}>
                    {w.steps.map(s=>(
                      <div key={s.id} title={s.label} style={{width:6,height:6,borderRadius:"50%",background:s.status==="done"?"#22C55E":"rgba(255,255,255,0.1)"}}/>
                    ))}
                  </div>
                  <span style={{fontSize:9,fontWeight:700,color:"#22C55E"}}>6/6 steps ✓</span>
                </div>
                <div style={{fontSize:10,color:"#64748b",display:"flex",alignItems:"center",gap:3}}>View <span style={{fontSize:8}}>›</span></div>
              </div>
            ))}
          </div>
        </div>}

      </div>}

    </div>

  );

}

function PatientsPage({patients,openPatient}){

  const [q,setQ]=useState("");

  const [type,setType]=useState("all");

  const [toast,setToast]=useState(null);

  const doToast=m=>{setToast(m);setTimeout(()=>setToast(null),2500);};

  const vis=patients.filter(p=>{

    if(type!=="all"&&p.type!==type)return false;

    if(!q)return true;

    const search=q.toLowerCase();

    return (p.name||"").toLowerCase().includes(search)||(p.email||"").toLowerCase().includes(search);

  });

  const STATUS_COLORS={active:C.green,inactive:"#64748b"};

  return(

    <div style={{display:"flex",flexDirection:"column",flex:1,overflow:"hidden"}}>

      {toast&&<div style={{position:"fixed",top:64,right:18,padding:"10px 16px",background:"rgba(0,109,255,0.06)",border:"1px solid rgba(80,140,255,0.18)",borderRadius:9,fontSize:12,color:C.green,zIndex:500,display:"flex",gap:6}}><Check size={12}/>{toast}</div>}

      {/* Toolbar */}

      <div style={{padding:"12px 16px",background:"#132238",borderBottom:"1px solid rgba(56,189,248,0.07)",display:"flex",gap:10,flexShrink:0,alignItems:"center"}}>

        <div style={{position:"relative",flex:1}}>

          <Search size={13} style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",color:"#CBD5E1"}}/>

          <input value={q} onChange={e=>setQ(e.target.value)} placeholder="Search by name or email…" style={{...inp,paddingLeft:30}}/>

        </div>

        <select value={type} onChange={e=>setType(e.target.value)} style={{...inp,width:"auto"}}>

          <option value="all">All Patients</option>

          <option value="nhs">NHS</option>

          <option value="private">Private</option>

        </select>

        <Btn v="primary" onClick={()=>setShowNewPatient(true)}><Plus size={12}/>Add Patient</Btn>

      </div>

      {/* Count */}

      <div style={{padding:"6px 16px",fontSize:11,color:"#CBD5E1",background:"#132238",borderBottom:"1px solid rgba(56,189,248,0.07)",flexShrink:0}}>

        Showing <strong>{vis.length}</strong> of {patients.length} patients

      </div>

      {/* Table */}

      <div style={{flex:1,overflowY:"auto"}}>

        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>

          <thead>

            <tr style={{background:"#0F1C34",borderBottom:`2px solid ${C.border}`}}>

              {["Patient","DOB","NHS No.","Dentist","Next Appt","Balance","Flags",""].map(h=>(

                <th key={h} style={{padding:"9px 14px",textAlign:"left",fontSize:9,fontWeight:800,color:"rgba(56,189,248,0.6)",letterSpacing:".07em",textTransform:"uppercase",fontWeight:800,whiteSpace:"nowrap"}}>{h}</th>

              ))}

            </tr>

          </thead>

          <tbody>

            {vis.length===0&&(

              <tr><td colSpan={8} style={{padding:"32px",textAlign:"center",color:"#CBD5E1",fontSize:13}}>

                No patients found matching "{q}"

              </td></tr>

            )}

            {vis.map((p,i)=>{

              const even=i%2===0;

              const bg=even?"#132238":"rgba(80,140,255,0.06)";

              const hoverBg="rgba(80,140,255,0.15)";

              return(

                <tr

                  key={p.id}

                  style={{background:bg,borderTop:i>0?"1px solid rgba(80,140,255,0.06)":"none",cursor:"pointer"}}

                  onClick={()=>openPatient(p.id)}

                  onMouseEnter={e=>e.currentTarget.style.background=hoverBg}

                  onMouseLeave={e=>e.currentTarget.style.background=bg}

                >

                  <td style={{padding:"10px 14px"}}>

                    <div style={{display:"flex",gap:9,alignItems:"center"}}>

                      <div style={{width:32,height:32,borderRadius:"50%",background:C.teal,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,color:"#132238",flexShrink:0}}>{p.ini}</div>

                      <div>

                        <div style={{fontSize:13,fontWeight:600}}>{p.name}</div>

                        <div style={{fontSize:10,color:"#CBD5E1"}}>{p.email}</div>

                      </div>

                    </div>

                  </td>

                  <td style={{padding:"10px 14px",color:"#CBD5E1",fontFamily:"ui-monospace,monospace",fontSize:11}}>{p.dob}</td>

                  <td style={{padding:"10px 14px",fontFamily:"ui-monospace,monospace",fontSize:11}}>

                    {p.nhs||<span style={{color:"#CBD5E1"}}>Private</span>}

                  </td>

                  <td style={{padding:"10px 14px",color:C.muted}}>{p.dentist}</td>

                  <td style={{padding:"10px 14px",fontSize:11,fontFamily:p.nextAppt?"monospace":"inherit",color:p.nextAppt?C.text:"#64748b"}}>

                    {p.nextAppt||"Not booked"}

                  </td>

                  <td style={{padding:"10px 14px"}}>

                    {p.balance>0

                      ?<span style={{fontWeight:700,color:p.overdue?C.red:C.amber,fontFamily:"ui-monospace,monospace"}}>£{f(p.balance)}</span>

                      :<span style={{color:C.green}}>£0.00</span>

                    }

                  </td>

                  <td style={{padding:"10px 14px"}}>

                    <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>

                      {(p.medAlerts||[]).map(a=>(

                        <span key={a} style={{fontSize:9,fontWeight:800,padding:"1px 6px",borderRadius:4,background:"rgba(239,68,68,0.12)",color:C.red}}>{a}</span>

                      ))}

                      {p.ep?.anxiety>=4&&<span style={{fontSize:9,fontWeight:700,padding:"1px 6px",borderRadius:4,background:"rgba(245,158,11,0.06)",color:C.amber}}>😰 Anxious</span>}

                      {p.ep?.triggers?.includes("injections")&&<span style={{fontSize:9,padding:"1px 6px",borderRadius:4,background:"rgba(245,158,11,0.06)",color:C.amber}}>💉</span>}

                      {p.ep?.extraTime&&<span style={{fontSize:9,padding:"1px 6px",borderRadius:4,background:"rgba(80,140,255,0.08)",color:C.blue}}>⏱ Extra time</span>}

                      {(p.ep?.flags||[]).some(flg=>flg.includes("♿")||flg.includes("Wheelchair"))&&<span style={{fontSize:9,fontWeight:700,padding:"1px 6px",borderRadius:4,background:"rgba(80,140,255,0.08)",color:C.blue}}>♿</span>}

                    </div>

                  </td>

                  <td style={{padding:"6px 10px"}} onClick={e=>e.stopPropagation()}>

                    <div style={{display:"flex",gap:4}}>

                      <button onClick={e=>{e.stopPropagation();openPatient(p.id);}} style={{padding:"4px 9px",border:`1.5px solid rgba(59,130,246,0.35)`,borderRadius:7,background:"#0F1C34",cursor:"pointer",fontSize:10,color:"#CBD5E1",fontWeight:600}}>Record</button>

                      <button onClick={e=>{e.stopPropagation();openPatient(p.id,"charting");}} style={{padding:"4px 9px",border:"none",borderRadius:7,background:C.teal,cursor:"pointer",fontSize:10,color:"#132238",fontWeight:700}}>🦷 Chart</button>

                    </div>

                  </td>

                </tr>

              );

            })}

          </tbody>

        </table>

      </div>

    </div>

  );

}

