function FeatureDetailModal({feature:f, currentPlan, onClose, onUpgrade}){
  const planLevel=f.plans[currentPlan];
  const isLocked=!planLevel||planLevel==="no";
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.55)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:800,padding:16}}>
      <div style={{background:"#132238",borderRadius:16,width:520,maxWidth:"100%",maxHeight:"85vh",overflowY:"auto",boxShadow:"0 24px 60px rgba(0,0,0,.3)"}}>
        <div style={{background:isLocked?"#132238":"linear-gradient(135deg,#006DFF,#38BDF8)",borderRadius:"16px 16px 0 0",padding:"20px 22px",position:"relative"}}>
          <button onClick={onClose} style={{position:"absolute",top:14,right:14,background:"rgba(255,255,255,.2)",border:"none",borderRadius:12,width:28,height:28,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:isLocked?"#64748b":"#132238",fontSize:16}}>✕</button>
          <div style={{fontSize:32,marginBottom:8}}>{f.icon}</div>
          <div style={{fontSize:18,fontWeight:800,color:isLocked?"#374151":"#132238",marginBottom:4}}>{f.name}</div>
          <div style={{fontSize:12,color:isLocked?"#64748b":"rgba(255,255,255,.75)"}}>{f.cat} · {f.included_in}</div>
        </div>
        <div style={{padding:"20px 22px"}}>
          <div style={{fontSize:12,color:"#F8FAFC",lineHeight:1.75,marginBottom:16}}>{f.long}</div>
          {f.benefits?.length>0&&<>
            <div style={{fontSize:11,fontWeight:800,color:"#CBD5E1",textTransform:"uppercase",letterSpacing:".05em",marginBottom:8}}>What's included</div>
            <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:16}}>
              {f.benefits.map((b,i)=><div key={i} style={{display:"flex",gap:8,fontSize:12,color:"#F8FAFC"}}><span style={{color:C.green,flexShrink:0}}>✓</span>{b}</div>)}
            </div>
          </>}
          {f.impact&&(f.impact.booked||f.impact.revenue)&&<div style={{padding:"12px 14px",background:"rgba(0,109,255,0.12)",border:`1px solid ${C.teal}30`,borderRadius:14,marginBottom:16}}>
            <div style={{fontSize:10,fontWeight:700,color:"#38BDF8",textTransform:"uppercase",marginBottom:4}}>Typical impact</div>
            {f.impact.booked&&<div style={{fontSize:13,fontWeight:800,color:"#38BDF8"}}>{f.impact.booked} {f.impact.label}</div>}
            {f.impact.revenue&&<div style={{fontSize:13,fontWeight:800,color:"#38BDF8"}}>£{f.impact.revenue.toLocaleString()} {f.impact.label}</div>}
          </div>}
          {isLocked
            ?<button onClick={onUpgrade} style={{width:"100%",padding:"12px",background:C.adminAccent,color:"#132238",border:"none",borderRadius:14,cursor:"pointer",fontSize:13,fontWeight:800}}>Upgrade to unlock this feature ↗</button>
            :<button onClick={onClose} style={{width:"100%",padding:"12px",background:"linear-gradient(135deg,#006DFF,#0057CC)",color:"#132238",boxShadow:"0 0 14px rgba(0,109,255,0.4)",border:"none",borderRadius:14,cursor:"pointer",fontSize:13,fontWeight:800,letterSpacing:"-.01em"}}>✓ Feature active on your plan</button>}
        </div>
      </div>
    </div>
  );
}

function ActiveFeatureCard({feature:f, plan, usage, onLearnMore}){
  const planLevel=f.plans[plan];
  const isLimited=planLevel==="limited"||planLevel==="basic";
  return(
    <div style={{background:"#132238",border:`1.5px solid ${C.border}`,borderRadius:16,padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>
      <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
        <span style={{fontSize:24,flexShrink:0}}>{f.icon}</span>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",gap:6,alignItems:"center",flexWrap:"wrap",marginBottom:3}}>
            <span style={{fontSize:13,fontWeight:800,letterSpacing:"-.01em"}}>{f.name}</span>
            {isLimited
              ?<span style={{fontSize:9,fontWeight:700,padding:"1px 7px",borderRadius:5,background:"rgba(245,158,11,0.06)",color:C.amber}}>LIMITED</span>
              :<span style={{fontSize:9,fontWeight:700,padding:"1px 7px",borderRadius:5,background:"rgba(0,109,255,0.1)",color:C.green}}>✓ ACTIVE</span>}
          </div>
          <div style={{fontSize:11,color:"#CBD5E1",lineHeight:1.5}}>{f.short}</div>
        </div>
      </div>
      {usage&&<div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        {usage.mins&&<div style={{fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:8,background:"rgba(0,109,255,0.12)",color:"#38BDF8"}}>{usage.mins} mins used</div>}
        {usage.booked&&<div style={{fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:8,background:"rgba(0,109,255,0.1)",color:C.green}}>{usage.booked} appts booked</div>}
        {usage.revenue&&<div style={{fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:8,background:"rgba(139,92,246,0.08)",color:C.purple}}>£{usage.revenue.toLocaleString()} revenue</div>}
        {usage.msgs&&<div style={{fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:8,background:"#132238",color:C.blue}}>{usage.msgs} messages</div>}
        {usage.sent&&<div style={{fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:8,background:"rgba(0,109,255,0.1)",color:C.green}}>{usage.sent} sent · {usage.read} read</div>}
      </div>}
      <button onClick={onLearnMore} style={{alignSelf:"flex-start",padding:"5px 12px",border:`1.5px solid rgba(59,130,246,0.35)`,borderRadius:7,background:"#0F1C34",cursor:"pointer",fontSize:11,color:"#CBD5E1",fontWeight:600}}>Details →</button>
    </div>
  );
}

function LockedFeatureCard({feature:f, onLearnMore, onUpgrade}){
  return(
    <div style={{background:"#132238",border:`1.5px dashed ${C.border}`,borderRadius:16,padding:"14px 16px",display:"flex",flexDirection:"column",gap:10,opacity:0.85}}>
      <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
        <span style={{fontSize:24,flexShrink:0,filter:"grayscale(0.6)"}}>{f.icon}</span>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",gap:6,alignItems:"center",flexWrap:"wrap",marginBottom:3}}>
            <span style={{fontSize:13,fontWeight:800,letterSpacing:"-.01em",color:"#CBD5E1"}}>{f.name}</span>
            <span style={{fontSize:9,fontWeight:700,padding:"1px 7px",borderRadius:5,background:"#0F1C34",color:"#CBD5E1"}}>🔒 {f.included_in}</span>
          </div>
          <div style={{fontSize:11,color:"#CBD5E1",lineHeight:1.5}}>{f.short}</div>
        </div>
      </div>
      <div style={{display:"flex",gap:7}}>
        <button onClick={onLearnMore} style={{flex:1,padding:"6px 10px",border:`1.5px solid rgba(59,130,246,0.35)`,borderRadius:7,background:"#132238",cursor:"pointer",fontSize:11,color:"#CBD5E1",fontWeight:600}}>Learn more</button>
        <button onClick={onUpgrade} style={{flex:1,padding:"6px 10px",border:"none",borderRadius:7,background:C.adminAccent,cursor:"pointer",fontSize:11,color:"#132238",fontWeight:700}}>Upgrade ↗</button>
      </div>
    </div>
  );
}

