// PAYMENTS — payment configuration and history
// ══════════════════════════════════════════════════════════════════════════════
function PaymentsPage(){
  const [providers,setProviders]=useState([
    {icon:"💳",name:"Stripe",status:"Connected",type:"Card",fees:"1.4% + 20p",apiKey:"sk_live_••••••••",webhookUrl:"https://pro.dental/webhooks/stripe"},
    {icon:"💰",name:"Chrysalis Finance",status:"Connected",type:"Finance",fees:"Revenue share",apiKey:"CRY-••••••••",webhookUrl:""},
    {icon:"🏦",name:"GoCardless",status:"Not connected",type:"DD",fees:"1% + 20p",apiKey:"",webhookUrl:""},
    {icon:"💳",name:"Square",status:"Not connected",type:"Card",fees:"1.75%",apiKey:"",webhookUrl:""},
  ]);
  const TXS=[{patient:"Amy Torres",amount:850,method:"Card (Stripe)",date:"10 May 2025",ref:"TXN001",status:"completed"},{patient:"John Mills",amount:73.50,method:"Cash",date:"14 May 2025",ref:"TXN002",status:"pending"},{patient:"Helen Rowe",amount:200,method:"Finance (Chrysalis)",date:"8 May 2025",ref:"TXN003",status:"completed"}];
  const [toast,setToast]=useState(null);
  const [connectModal,setConnectModal]=useState(null);
  const [apiKeyInput,setApiKeyInput]=useState("");
  const doToast=m=>{setToast(m);setTimeout(()=>setToast(null),2000);};
  const connectProvider=(name)=>{
    if(!apiKeyInput.trim()){doToast("⚠ API key required");return;}
    setProviders(p=>p.map(pr=>pr.name!==name?pr:{...pr,status:"Connected",apiKey:apiKeyInput}));
    setConnectModal(null);setApiKeyInput("");doToast("✓ "+name+" connected successfully — test transaction sent");
  };
  return(
    <div style={{padding:20,overflowY:"auto",flex:1,background:"#071428",backgroundImage:"radial-gradient(ellipse at 85% 5%,rgba(80,140,255,0.08) 0%,transparent 45%),radial-gradient(ellipse at 15% 80%,rgba(59,130,246,0.05) 0%,transparent 40%)"}}>
      {toast&&<div style={{position:"fixed",top:64,right:18,padding:"8px 16px",background:"rgba(0,109,255,0.06)",border:"1px solid rgba(80,140,255,0.18)",borderRadius:9,fontSize:12,color:C.green,zIndex:500}}>{toast}</div>}

      {/* Connect Modal */}
      {connectModal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:800}}>
        <div style={{background:"#132238",borderRadius:16,width:400,padding:24,boxShadow:"0 24px 60px rgba(0,0,0,0.6),0 0 40px rgba(0,109,255,0.1)"}}>
          <div style={{fontSize:16,fontWeight:800,marginBottom:4}}>{connectModal.icon} Connect {connectModal.name}</div>
          <div style={{fontSize:11,color:"#CBD5E1",marginBottom:16}}>{connectModal.type} · {connectModal.fees}</div>
          <div style={{marginBottom:12}}>
            <label style={{fontSize:11,fontWeight:700,color:"#CBD5E1",display:"block",marginBottom:4}}>API Key / Secret Key</label>
            <input value={apiKeyInput} onChange={e=>setApiKeyInput(e.target.value)} placeholder={connectModal.name==="GoCardless"?"access_••••••••":"sk_live_••••••••"}
              style={{width:"100%",padding:"8px 10px",border:"1px solid rgba(80,140,255,0.16)",borderRadius:12,fontSize:12,fontFamily:"ui-monospace,monospace",outline:"none",boxSizing:"border-box"}}/>
          </div>
          <div style={{padding:"8px 10px",background:"rgba(80,140,255,0.06)",borderRadius:12,fontSize:10,color:"#2563FF",marginBottom:14}}>
            ✓ Encrypted in transit · Stored securely · Test transaction sent on connect
          </div>
          <div style={{display:"flex",gap:8}}>
            <button onClick={()=>{setConnectModal(null);setApiKeyInput("");}} style={{flex:1,padding:"9px",border:"1px solid rgba(80,140,255,0.16)",borderRadius:12,background:"#0F1C34",cursor:"pointer",fontSize:11,color:"#CBD5E1"}}>Cancel</button>
            <button onClick={()=>connectProvider(connectModal.name)} style={{flex:2,padding:"9px",background:"linear-gradient(135deg,#006DFF,#0057CC)",color:"#132238",boxShadow:"0 0 14px rgba(0,109,255,0.4)",border:"none",borderRadius:12,cursor:"pointer",fontSize:12,fontWeight:700}}>Connect {connectModal.name}</button>
          </div>
        </div>
      </div>}

      <div style={{fontSize:15,fontWeight:800,marginBottom:14}}>Payment Configuration</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {providers.map(p=><div key={p.name} style={{background:"#132238",border:`1px solid ${p.status==="Connected"?C.teal:C.border}`,borderRadius:16,padding:14,display:"flex",flexDirection:"column",gap:8}}>
          <div style={{display:"flex",gap:8,alignItems:"center"}}><span style={{fontSize:20}}>{p.icon}</span><div><div style={{fontSize:12,fontWeight:700}}>{p.name}</div><div style={{fontSize:10,color:"#CBD5E1"}}>{p.type} · {p.fees}</div></div></div>
          <Chip color={p.status==="Connected"?C.green:C.muted}>{p.status}</Chip>
          {p.status==="Connected"&&<div style={{fontSize:9,color:"#CBD5E1",fontFamily:"ui-monospace,monospace",background:"#0F1C34",padding:"2px 6px",borderRadius:4}}>{p.apiKey}</div>}
          {p.status!=="Connected"&&<button onClick={()=>setConnectModal(p)} style={{padding:"6px",border:`1px solid ${C.teal}`,borderRadius:7,background:"rgba(0,109,255,0.12)",cursor:"pointer",fontSize:10,color:"#38BDF8",fontWeight:700}}>Connect</button>}
        </div>)}
      </div>
      <div style={{background:"#132238",border:"1px solid rgba(56,189,248,0.12)",borderRadius:16,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:"1px solid rgba(56,189,248,0.07)",transition:"background .12s",cursor:"pointer",fontSize:13,fontWeight:800,letterSpacing:"-.01em"}}>Recent Transactions</div>
        {TXS.map((t,i)=><div key={t.ref} style={{display:"flex",gap:12,padding:"10px 14px",borderTop:i>0?`1px solid rgba(56,189,248,0.07)`:"none",alignItems:"center"}}>
          <div style={{flex:1}}><div style={{fontSize:12,fontWeight:600}}>{t.patient}</div><div style={{fontSize:10,color:"#CBD5E1"}}>{t.method} · {t.date} · {t.ref}</div></div>
          <div style={{fontSize:14,fontWeight:800,color:t.status==="completed"?C.teal:C.amber,fontFamily:"ui-monospace,monospace"}}>£{t.amount.toFixed(2)}</div>
          <Chip color={t.status==="completed"?C.green:C.amber}>{t.status==="completed"?"Paid":"Pending"}</Chip>
        </div>)}
      </div>
    </div>
  );
}

