// ── Encrypted Report / Email Modal ──────────────────────────────────────────
function EncryptedReportModal({patient,reportType,onClose,onSend,encryptedReportsEnabled}){
  const [sending,setSending]=useState(false);
  const [sent,setSent]=useState(false);
  const [includeInvoice,setIncludeInvoice]=useState(false);

  // Simulate DOB-based password (never shown in the email)
  const dobFormatted=patient?.dob?.replace(/[^0-9]/g,"").replace(/(\d{2})\/(\d{2})\/(\d{4})/,"$1$2$3")||"DDMMYYYY";
  const fileName=`${(patient?.name||"Patient").replace(/\s+/g,"_")}_${reportType.replace(/\s+/g,"_")}_${new Date().toISOString().slice(0,10)}.pdf`;
  const encFileName=encryptedReportsEnabled?fileName.replace(".pdf","_SECURE.pdf"):fileName;

  const handleSend=()=>{
    setSending(true);
    setTimeout(()=>{
      setSending(false);
      setSent(true);
      onSend?.({
        type:reportType,
        fileName:encFileName,
        encrypted:encryptedReportsEnabled,
        email:patient?.email,
        patientId:patient?.id,
        patientName:patient?.name,
        sentBy:"Current User",
      });
      setTimeout(()=>{onClose?.();},1600);
    },1400);
  };

  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:990,backdropFilter:"blur(4px)"}} onClick={e=>{if(e.target===e.currentTarget)onClose?.();}}>
      <div style={{background:"#0F1C34",border:"1px solid rgba(80,140,255,0.3)",borderRadius:20,width:500,padding:28,boxShadow:"0 32px 80px rgba(0,0,0,0.6)"}}>
        
        {/* Header */}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div style={{display:"flex",gap:12,alignItems:"center"}}>
            <div style={{width:44,height:44,borderRadius:14,background:encryptedReportsEnabled?"rgba(34,197,94,0.12)":"rgba(80,140,255,0.12)",border:"1.5px solid "+(encryptedReportsEnabled?"rgba(34,197,94,0.3)":"rgba(80,140,255,0.3)"),display:"flex",alignItems:"center",justifyContent:"center",fontSize:22}}>{encryptedReportsEnabled?"🔒":"📄"}</div>
            <div>
              <div style={{fontSize:15,fontWeight:800,color:"#F8FAFC"}}>{encryptedReportsEnabled?"Send Encrypted Report":"Send Report"}</div>
              <div style={{fontSize:11,color:"#CBD5E1"}}>{patient?.name} · {patient?.email}</div>
            </div>
          </div>
          <button onClick={onClose} style={{border:"none",background:"transparent",cursor:"pointer",color:"#94A3B8",fontSize:20,lineHeight:1}}>✕</button>
        </div>

        {/* Encryption status banner */}
        {encryptedReportsEnabled?(
          <div style={{padding:"12px 16px",background:"rgba(34,197,94,0.08)",border:"1px solid rgba(34,197,94,0.25)",borderRadius:12,marginBottom:16,display:"flex",gap:10,alignItems:"flex-start"}}>
            <span style={{fontSize:16,flexShrink:0}}>🔒</span>
            <div>
              <div style={{fontSize:12,fontWeight:700,color:"#4ADE80",marginBottom:3}}>PDF will be password protected</div>
              <div style={{fontSize:11,color:"#CBD5E1",lineHeight:1.5}}>
                The report PDF is encrypted with the patient's date of birth as the password (DDMMYYYY format). The actual DOB is <strong style={{color:"#F8FAFC"}}>not included</strong> in the email.
              </div>
            </div>
          </div>
        ):(
          <div style={{padding:"10px 14px",background:"rgba(245,158,11,0.08)",border:"1px solid rgba(245,158,11,0.25)",borderRadius:10,marginBottom:16,fontSize:11,color:"#FCD34D"}}>
            ⚠️ Encrypted reports are disabled in settings. The PDF will be sent without password protection.
          </div>
        )}

        {/* File preview */}
        <div style={{padding:"12px 14px",background:"rgba(2,8,23,0.6)",border:"1px solid rgba(80,140,255,0.2)",borderRadius:12,marginBottom:14,display:"flex",gap:12,alignItems:"center"}}>
          <div style={{width:36,height:42,background:"#0F1C34",border:"1px solid rgba(80,140,255,0.3)",borderRadius:6,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>📋</div>
          <div style={{flex:1}}>
            <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC",marginBottom:2}}>{encFileName}</div>
            <div style={{fontSize:10,color:"#94A3B8"}}>
              {reportType} · {encryptedReportsEnabled?"Password: DOB in DDMMYYYY format":"No password"}
            </div>
          </div>
          {encryptedReportsEnabled&&<div style={{fontSize:9,padding:"3px 9px",background:"rgba(34,197,94,0.12)",border:"1px solid rgba(34,197,94,0.25)",borderRadius:20,color:"#4ADE80",fontWeight:700}}>🔒 ENCRYPTED</div>}
        </div>

        {/* Email preview */}
        <div style={{marginBottom:16}}>
          <div style={{fontSize:11,fontWeight:700,color:"#CBD5E1",marginBottom:8,textTransform:"uppercase",letterSpacing:".05em"}}>Email message to patient</div>
          <div style={{background:"rgba(2,8,23,0.5)",border:"1px solid rgba(80,140,255,0.15)",borderRadius:10,padding:"12px 14px",fontSize:12,color:"#CBD5E1",lineHeight:1.65}}>
            <div style={{color:"#F8FAFC",fontWeight:600,marginBottom:6}}>Subject: Your treatment report from Riverside Dentistry</div>
            <div>Dear {patient?.name?.split(" ")[0]||"Patient"},</div>
            <br/>
            <div>Please find your {reportType.toLowerCase()} attached as a secure PDF.</div>
            {encryptedReportsEnabled&&<>
              <br/>
              <div style={{padding:"8px 10px",background:"rgba(34,197,94,0.07)",borderLeft:"3px solid #22C55E",borderRadius:"0 6px 6px 0",fontSize:11}}>
                🔒 <strong style={{color:"#F8FAFC"}}>To open this document:</strong> enter your date of birth in DDMMYYYY format as the password (e.g. if your date of birth is 14 March 1990, enter 14031990).
              </div>
            </>}
            <br/>
            <div>If you have any questions, please contact us on 0208 123 4567.</div>
            <br/>
            <div style={{color:"#94A3B8"}}>Kind regards,<br/>Riverside Dentistry</div>
          </div>
        </div>

        {/* Include invoice option */}
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:18,padding:"10px 14px",background:"rgba(80,140,255,0.06)",borderRadius:10}}>
          <div onClick={()=>setIncludeInvoice(!includeInvoice)} style={{width:20,height:20,borderRadius:5,border:"1.5px solid rgba(80,140,255,0.4)",background:includeInvoice?"#2563FF":"transparent",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,color:"#fff",flexShrink:0}}>{includeInvoice?"✓":""}</div>
          <div>
            <div style={{fontSize:12,fontWeight:600,color:"#F8FAFC"}}>Also attach {encryptedReportsEnabled?"encrypted ":""}invoice</div>
            <div style={{fontSize:10,color:"#94A3B8"}}>Include the payment receipt in the same {encryptedReportsEnabled?"secure ":""}email</div>
          </div>
        </div>

        {/* Send button */}
        {!sent?(
          <div style={{display:"flex",gap:10}}>
            <button onClick={onClose} style={{flex:1,padding:"11px",border:"1px solid rgba(80,140,255,0.2)",borderRadius:11,background:"transparent",cursor:"pointer",fontSize:13,color:"#CBD5E1",fontFamily:"inherit"}}>Cancel</button>
            <button onClick={handleSend} disabled={sending} style={{flex:2,padding:"11px",background:encryptedReportsEnabled?"linear-gradient(135deg,#16a34a,#15803d)":"linear-gradient(135deg,#2563FF,#1D4ED8)",border:"none",borderRadius:11,cursor:sending?"wait":"pointer",fontSize:13,fontWeight:700,color:"#fff",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:8,boxShadow:encryptedReportsEnabled?"0 2px 12px rgba(22,163,74,0.35)":"0 2px 12px rgba(37,99,255,0.35)"}}>
              {sending?<><span style={{width:14,height:14,border:"2px solid rgba(255,255,255,0.3)",borderTop:"2px solid #fff",borderRadius:"50%",display:"inline-block"}}/>Sending...</>
               :<>{encryptedReportsEnabled?"🔒 Send Encrypted Report":"📧 Send Report"}</>}
            </button>
          </div>
        ):(
          <div style={{textAlign:"center",padding:"12px",background:"rgba(34,197,94,0.1)",border:"1px solid rgba(34,197,94,0.3)",borderRadius:11,fontSize:13,fontWeight:700,color:"#4ADE80",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
            ✓ {encryptedReportsEnabled?"Encrypted report":"Report"} sent to {patient?.email}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Encrypted Report Log Component (for Settings & Patient Record) ───────────
function EncryptedReportLogView({log,patientId}){
  const items=(patientId?log.filter(l=>l.patientId===patientId):log)||[];
  return(
    <div>
      {items.length===0&&<div style={{textAlign:"center",padding:"24px",color:"#CBD5E1",fontSize:13}}>No secure reports sent yet</div>}
      {items.map(entry=>(
        <div key={entry.id} style={{display:"flex",gap:12,padding:"10px 14px",borderBottom:"1px solid rgba(80,140,255,0.1)",alignItems:"center"}}>
          <div style={{width:32,height:32,borderRadius:10,background:entry.encrypted?"rgba(34,197,94,0.12)":"rgba(80,140,255,0.1)",border:"1px solid "+(entry.encrypted?"rgba(34,197,94,0.25)":"rgba(80,140,255,0.2)"),display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>{entry.encrypted?"🔒":"📄"}</div>
          <div style={{flex:1}}>
            <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC"}}>{entry.fileName||entry.type}</div>
            <div style={{fontSize:10,color:"#94A3B8"}}>{entry.patientName} · Sent by {entry.sentBy}</div>
          </div>
          <div style={{textAlign:"right",flexShrink:0}}>
            {entry.encrypted&&<div style={{fontSize:9,padding:"2px 8px",background:"rgba(34,197,94,0.12)",border:"1px solid rgba(34,197,94,0.2)",borderRadius:20,color:"#4ADE80",fontWeight:700,marginBottom:3}}>🔒 Encrypted</div>}
            <div style={{fontSize:10,color:"#94A3B8"}}>{entry.sentAt?new Date(entry.sentAt).toLocaleString("en-GB",{day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"}):""}</div>
          </div>
        </div>
      ))}
    </div>
  );
}



// ═══════════════════════════════════════════════════════════════════════════
// SECURE DOCUMENT SEND SYSTEM
// Handles report generation, sending, send history, resend
// (PDFs are password-protected with patient DOB — staff see "Send" only)
// ═══════════════════════════════════════════════════════════════════════════

// ── Send Report Modal (used by both Doctor & Reception workflows) ────────────
function SendReportModal({patient, reportType, trigger, onClose, onSend, existingLog=[]}) {
  const [step, setStep] = useState('preview'); // preview | sending | done
  const [includeInvoice, setIncludeInvoice] = useState(false);
  const [customNote, setCustomNote] = useState('');

  // Check if already sent
  const alreadySent = existingLog.filter(e => e.patientId === patient?.id && e.type === reportType);
  const lastSent = alreadySent[0];

  // Format email — DOB-based password, never shown in UI
  const formatEmail = () => ({
    to: patient?.email || 'patient@email.com',
    subject: `Your ${reportType} from Riverside Dentistry`,
    body: `Dear ${patient?.name?.split(' ')[0] || 'Patient'},\n\nPlease find your ${reportType.toLowerCase()} attached.\n\nTo open the attached document, please use your date of birth in DDMMYYYY format as the password.\n\n${customNote ? customNote + '\n\n' : ''}If you have any questions, please contact us on 0208 123 4567.\n\nKind regards,\nRiverside Dentistry`,
  });

  const doSend = () => {
    setStep('sending');
    setTimeout(() => {
      const entry = {
        id: 'SR' + Date.now(),
        patientId: patient?.id,
        patientName: patient?.name,
        type: reportType,
        email: patient?.email,
        sentAt: new Date().toISOString(),
        sentBy: 'Current User',
        status: 'delivered',
        fileName: `${patient?.name?.replace(/\s+/g,'_')}_${reportType.replace(/\s+/g,'_')}_${new Date().toISOString().slice(0,10)}.pdf`,
        trigger,
        resendCount: 0,
      };
      onSend?.(entry);
      setStep('done');
    }, 1500);
  };

  const email = formatEmail();

  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:990}} onClick={e=>{if(e.target===e.currentTarget)onClose?.();}}>
      <div style={{background:'#0F1C34',border:'1px solid rgba(80,140,255,0.3)',borderRadius:20,width:520,maxHeight:'90vh',overflow:'auto',padding:26,boxShadow:'0 32px 80px rgba(0,0,0,0.6)'}}>

        {/* Header */}
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
          <div style={{display:'flex',gap:11,alignItems:'center'}}>
            <div style={{width:42,height:42,borderRadius:13,background:'rgba(37,99,255,0.12)',border:'1.5px solid rgba(80,140,255,0.3)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:20}}>📧</div>
            <div>
              <div style={{fontSize:15,fontWeight:800,color:'#F8FAFC'}}>Send {reportType}</div>
              <div style={{fontSize:11,color:'#CBD5E1'}}>{patient?.name} · {email.to}</div>
            </div>
          </div>
          <button onClick={onClose} style={{border:'none',background:'transparent',cursor:'pointer',color:'#94A3B8',fontSize:20}}>✕</button>
        </div>

        {/* Already sent notice */}
        {lastSent && step === 'preview' && (
          <div style={{padding:'10px 14px',background:'rgba(245,158,11,0.08)',border:'1px solid rgba(245,158,11,0.25)',borderRadius:10,marginBottom:14,fontSize:12,color:'#FCD34D',display:'flex',gap:8,alignItems:'center'}}>
            <span>⚠</span>
            <span>Previously sent {new Date(lastSent.sentAt).toLocaleString('en-GB',{day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'})} by {lastSent.sentBy}. This will resend.</span>
          </div>
        )}

        {step === 'preview' && <>
          {/* Document preview */}
          <div style={{padding:'12px 14px',background:'rgba(2,8,23,0.5)',border:'1px solid rgba(80,140,255,0.18)',borderRadius:12,marginBottom:14,display:'flex',gap:12,alignItems:'center'}}>
            <div style={{width:38,height:46,background:'#132238',border:'1px solid rgba(80,140,255,0.25)',borderRadius:6,display:'flex',alignItems:'center',justifyContent:'center',fontSize:20,flexShrink:0}}>📋</div>
            <div style={{flex:1}}>
              <div style={{fontSize:12,fontWeight:700,color:'#F8FAFC',marginBottom:2}}>
                {patient?.name?.replace(/\s+/g,'_')}_{reportType.replace(/\s+/g,'_')}_{new Date().toISOString().slice(0,10)}.pdf
              </div>
              <div style={{fontSize:10,color:'#94A3B8'}}>Password protected · Patient opens with their date of birth</div>
            </div>
          </div>

          {/* Email preview */}
          <div style={{marginBottom:14}}>
            <div style={{fontSize:10,fontWeight:700,color:'#94A3B8',marginBottom:7,textTransform:'uppercase',letterSpacing:'.05em'}}>Email preview</div>
            <div style={{background:'rgba(2,8,23,0.4)',border:'1px solid rgba(80,140,255,0.15)',borderRadius:10,padding:'12px 14px',fontSize:12,color:'#CBD5E1',lineHeight:1.65}}>
              <div style={{color:'#F8FAFC',fontWeight:600,marginBottom:5}}>To: {email.to}</div>
              <div style={{color:'#F8FAFC',fontWeight:600,marginBottom:8}}>Subject: {email.subject}</div>
              <div style={{whiteSpace:'pre-line'}}>{email.body}</div>
            </div>
          </div>

          {/* Optional note */}
          <div style={{marginBottom:14}}>
            <div style={{fontSize:10,fontWeight:700,color:'#94A3B8',marginBottom:5,textTransform:'uppercase',letterSpacing:'.05em'}}>Add a note (optional)</div>
            <input value={customNote} onChange={e=>setCustomNote(e.target.value)} placeholder='e.g. Please review your treatment plan...'
              style={{width:'100%',padding:'9px 12px',background:'#132238',border:'1.5px solid rgba(80,140,255,0.25)',borderRadius:9,color:'#F8FAFC',fontSize:12,fontFamily:'inherit',outline:'none',boxSizing:'border-box'}}/>
          </div>

          {/* Include invoice toggle */}
          <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:18,padding:'10px 14px',background:'rgba(80,140,255,0.05)',borderRadius:10}}>
            <div onClick={()=>setIncludeInvoice(!includeInvoice)} style={{width:20,height:20,borderRadius:5,border:'1.5px solid rgba(80,140,255,0.35)',background:includeInvoice?'#2563FF':'transparent',cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,color:'#fff',flexShrink:0}}>{includeInvoice&&'✓'}</div>
            <div><div style={{fontSize:12,fontWeight:600,color:'#F8FAFC'}}>Also send invoice</div><div style={{fontSize:10,color:'#94A3B8'}}>Include payment receipt in the same email</div></div>
          </div>

          <div style={{display:'flex',gap:9}}>
            <button onClick={onClose} style={{flex:1,padding:'11px',border:'1px solid rgba(80,140,255,0.2)',borderRadius:11,background:'transparent',cursor:'pointer',fontSize:13,color:'#CBD5E1',fontFamily:'inherit'}}>Cancel</button>
            <button onClick={doSend} style={{flex:2,padding:'11px',background:'linear-gradient(135deg,#2563FF,#1D4ED8)',border:'none',borderRadius:11,cursor:'pointer',fontSize:13,fontWeight:800,color:'#fff',fontFamily:'inherit',boxShadow:'0 2px 12px rgba(37,99,255,0.35)'}}>
              {lastSent ? '↩ Resend' : '📧 Send'}
            </button>
          </div>
        </>}

        {step === 'sending' && (
          <div style={{textAlign:'center',padding:'32px 0'}}>
            <div style={{width:48,height:48,border:'3px solid rgba(59,130,246,0.2)',borderTop:'3px solid #3B82F6',borderRadius:'50%',margin:'0 auto 14px',animation:'spin 1s linear infinite'}}/>
            <div style={{fontSize:14,fontWeight:700,color:'#F8FAFC',marginBottom:4}}>Sending…</div>
            <div style={{fontSize:11,color:'#CBD5E1'}}>Preparing and sending document to {email.to}</div>
          </div>
        )}

        {step === 'done' && (
          <div style={{textAlign:'center',padding:'24px 0'}}>
            <div style={{fontSize:40,marginBottom:10}}>✅</div>
            <div style={{fontSize:15,fontWeight:800,color:'#F8FAFC',marginBottom:4}}>Sent</div>
            <div style={{fontSize:12,color:'#CBD5E1',marginBottom:16}}>{reportType} sent to {email.to}</div>
            <div style={{padding:'10px 14px',background:'rgba(34,197,94,0.08)',border:'1px solid rgba(34,197,94,0.25)',borderRadius:10,fontSize:11,color:'#94A3B8'}}>
              Logged · {new Date().toLocaleString('en-GB',{day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'})} by You
            </div>
            <button onClick={onClose} style={{marginTop:16,padding:'10px 32px',background:'#2563FF',border:'none',borderRadius:10,cursor:'pointer',fontSize:13,fontWeight:700,color:'#fff',fontFamily:'inherit'}}>Done</button>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Send History Log Row ─────────────────────────────────────────────────────
function SendHistoryRow({entry, onResend}) {
  const statusColor = entry.status==='delivered'?'#22C55E':entry.status==='failed'?'#EF4444':'#F59E0B';
  const statusLabel = entry.status==='delivered'?'Sent':entry.status==='failed'?'Failed':'Pending';
  return (
    <div style={{display:'flex',gap:12,padding:'11px 16px',borderBottom:'1px solid rgba(80,140,255,0.1)',alignItems:'center',background:'#0F1C34'}}>
      <div style={{width:34,height:34,borderRadius:10,background:statusColor+'14',border:`1px solid ${statusColor}30`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:15,flexShrink:0}}>
        {entry.status==='delivered'?'✅':entry.status==='failed'?'❌':'⏳'}
      </div>
      <div style={{flex:1,minWidth:0}}>
        <div style={{fontSize:12,fontWeight:700,color:'#F8FAFC',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{entry.fileName||entry.type}</div>
        <div style={{fontSize:10,color:'#94A3B8'}}>To: {entry.email} · Sent by {entry.sentBy}</div>
      </div>
      <div style={{textAlign:'right',flexShrink:0}}>
        <div style={{fontSize:10,fontWeight:700,color:statusColor,marginBottom:3}}>{statusLabel}</div>
        <div style={{fontSize:9,color:'#94A3B8'}}>{entry.sentAt?new Date(entry.sentAt).toLocaleString('en-GB',{day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'}):''}</div>
        <button onClick={()=>onResend?.(entry)} style={{marginTop:4,padding:'2px 10px',border:'1px solid rgba(80,140,255,0.25)',borderRadius:6,background:'transparent',cursor:'pointer',fontSize:9,fontWeight:700,color:'#60A5FA',fontFamily:'inherit'}}>Resend</button>
      </div>
    </div>
  );
}

// ── Payment Complete → Send Prompt ───────────────────────────────────────────
function PaymentSendPrompt({patient, existingLog=[], onSend, onDismiss}) {
  const alreadySent = existingLog.some(e=>e.patientId===patient?.id && e.type==='Treatment Report');
  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.6)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:970}} onClick={e=>{if(e.target===e.currentTarget)onDismiss?.();}}>
      <div style={{background:'#0F1C34',border:'1px solid rgba(80,140,255,0.28)',borderRadius:18,width:400,padding:24,boxShadow:'0 24px 60px rgba(0,0,0,0.5)'}}>
        <div style={{fontSize:22,textAlign:'center',marginBottom:10}}>💷</div>
        <div style={{fontSize:15,fontWeight:800,color:'#F8FAFC',textAlign:'center',marginBottom:6}}>Payment received</div>
        <div style={{fontSize:12,color:'#CBD5E1',textAlign:'center',marginBottom:18}}>
          {alreadySent ? (
            <span>The treatment report was <span style={{color:'#4ADE80',fontWeight:700}}>already sent</span> to {patient?.email}.</span>
          ) : (
            'Would you like to send the treatment report to the patient?'
          )}
        </div>
        <div style={{display:'flex',gap:9}}>
          <button onClick={onDismiss} style={{flex:1,padding:'10px',border:'1px solid rgba(80,140,255,0.2)',borderRadius:10,background:'transparent',cursor:'pointer',fontSize:13,color:'#CBD5E1',fontFamily:'inherit'}}>
            {alreadySent ? 'Close' : 'Skip'}
          </button>
          <button onClick={()=>onSend?.(alreadySent)} style={{flex:2,padding:'10px',background:alreadySent?'rgba(80,140,255,0.12)':'linear-gradient(135deg,#2563FF,#1D4ED8)',border:alreadySent?'1px solid rgba(80,140,255,0.28)':'none',borderRadius:10,cursor:'pointer',fontSize:13,fontWeight:800,color:alreadySent?'#60A5FA':'#fff',fontFamily:'inherit'}}>
            {alreadySent ? '↩ Resend Report' : '📧 Send Report'}
          </button>
        </div>
      </div>
    </div>
  );
}



export default function App(){
  const [user,setUser]=useState(null);
  const [userPerms,setUserPerms]=useState(INIT_USER_PERMS());
  const [featureUserCfg,setFeatureUserCfg]=useState(FEATURE_USER_CFG_INIT());
  const [showNewPatient,setShowNewPatient]=useState(false);
  const [showBookAppt,setShowBookAppt]=useState(false);
  const [encryptedReportLog,setEncryptedReportLog]=useState([
    {id:"ERL001",patientId:"P1",patientName:"John Mills",type:"Treatment Report",sentAt:"2025-05-14T09:15:00Z",sentBy:"Dr. S. Patel",encrypted:true,fileName:"JohnMills_Treatment_20250514.pdf"},
    {id:"ERL002",patientId:"P2",patientName:"Sarah Chen",type:"Invoice",sentAt:"2025-05-13T14:30:00Z",sentBy:"Emma Wilson",encrypted:true,fileName:"SarahChen_Invoice_20250513.pdf"},
  ]);
  const addEncryptedReportLog=(entry)=>setEncryptedReportLog(p=>[{
    id:"ERL"+Date.now(),sentAt:new Date().toISOString(),...entry
  },...p]);
  const encryptedReportsEnabled=featureUserCfg?.encrypted_reports?.enabled!==false;
  const [permAuditLog,setPermAuditLog]=useState(PERM_AUDIT_INIT);
  const addPermAudit=(action,target,detail,diff)=>setPermAuditLog(p=>[{
    id:"PA"+String(Date.now()).slice(-6),
    ts:new Date().toISOString(),
    actorName:user?.name||"System",
    action,target,detail,diff,
  },...p.slice(0,199)]);
  const [page,setPage]=useState("dashboard");
  const [patientId,setPatientId]=useState(null);
  const [patientDefaultTab,setPatientDefaultTab]=useState("details");
  const [alertQueue,setAlertQueue]=useState([]);
  const [acked,setAcked]=useState(new Set());
  const [notifs,setNotifs]=useState([{id:"N1",type:"alert",title:"Patient waiting too long",desc:"Tom Bright — 22 min",at:"09:43",read:false},{id:"N2",type:"task",title:"FP17 reminder",desc:"Amy Torres — 2 days overdue",at:"09:00",read:false},{id:"N3",type:"lab",title:"Lab case overdue",desc:"Sarah Chen — Crown UR6",at:"08:30",read:false},{id:"N4",type:"clinical",title:"Clinical note incomplete",desc:"Tom Bright — 13 May",at:"08:00",read:true}]);
  const [waiting,setWaiting]=useState(WAITING_INIT);
  const [copilotOpen,setCopilotOpen]=useState(false);
  const [copilotSubscribed,setCopilotSubscribed]=useState(false);

  const tasks=useMemo(()=>[{title:"Submit FP17 — Amy Torres",priority:"urgent",done:false,src:"auto"},{title:"Confirm tomorrow's appointments",priority:"urgent",done:false,src:"auto"},{title:"Chase lab — Sarah Chen",priority:"normal",done:false,src:"auto"}],[]);

  const [prevPatientId,setPrevPatientId]=useState(null);
  const openPatient=useCallback((pid,tab)=>{
    const pt=PATIENTS.find(p=>p.id===pid);if(!pt)return;
    setPrevPatientId(patientId);
    setPatientId(pid);
    setPatientDefaultTab(tab||"details");
    const alertFeature=GLOBAL_FEATURE_CONFIG.find(f=>f.id==="mandatory_alert_ack");
    const alertsEnabled=alertFeature?alertFeature.enabled:true;
    if(pt.alerts.length>0&&alertsEnabled)setAlertQueue([pt]);
  },[patientId]);
  const ackAlert=()=>{setAlertQueue([]);};

  const renderContent=()=>{
    if(patientId&&PATIENTS.find(p=>p.id===patientId))return <PatientRecord patient={PATIENTS.find(p=>p.id===patientId)} user={user} defaultTab={patientDefaultTab||"details"} openPatient={openPatient} onBack={()=>{setPatientId(null);setAlertQueue([]);setPatientDefaultTab("details");}}/>;
    if(user?.role==="superadmin"){
      const AP={
        admin_dash:<AdminDashboard/>,
        admin_practices:<AdminPractices/>,
        admin_pricing:<AdminPricing/>,
        admin_updates:<AdminUpdates/>,
        admin_users:<AdminUsers/>,
        admin_support:<AdminSupport/>,
        admin_receptionai:<AdminReceptionAI/>,
        admin_features:<AdminFeatures/>,
        admin_tickets:<AdminTickets/>,
        admin_support_config:<AdminSupportConfig/>,
        admin_seat_control:<AdminSeatControl/>,
        admin_ai:<AdminDashboard/>,
        admin_data:<AdminDataManager/>,
        admin_monitoring:<AdminSystemMonitoring/>,
        admin_security:<AdminSecurityCompliance/>,
        admin_backup:<AdminCloudBackup/>,
        admin_tx_plans:<AdminDashboard/>,
        admin_audit:<AdminActivityLog/>,
        admin_appt_audit:<AdminActivityLog/>,
        admin_integrations:<IntegrationsPage/>,
      };
      return AP[page]||<GenericPage page={page}/>;
    }
    const PP={
      nba:<NBAPage role={user?.role||"reception"} setPage={p=>{setPage(p);setPatientId(null);}} openPatient={openPatient}/>,
      dashboard:<Dashboard openPatient={openPatient} waiting={waiting} setWaiting={setWaiting} user={user} setPage={p=>{setPage(p);setPatientId(null);}}/>,
      calendar:<CalendarPage openPatient={openPatient} user={user}/>,
      waiting:<WaitingPage waiting={waiting} setWaiting={setWaiting} user={user} openPatient={openPatient} setNotifs={n=>setNotifs(n)}/>,
      patients:<PatientsPage patients={PATIENTS} openPatient={openPatient}/>,
      // charting: accessed via patient record, not standalone
      notes:<ClinicalNotesPage openPatient={openPatient}/>,
      xray:<XRayPage/>,
      fp17:<FP17Page/>,
      uda:<UDAPage/>,
      teamchat:<TeamChat user={user}/>,
      whatsapp:<WhatsAppPage/>,
      receptionai:<ReceptionAIPage rxEnabled={true} user={user}/>,
      comms:<CommsPage/>,
      recovery:<RevenueRecoveryPage/>,
      shortnotice:<ShortNoticePage/>,
      lab:<LabPage/>,
      accounts:<AccountsPage/>,
      payments:<PaymentsPage/>,
      reports:<ReportsPage/>,
      myreports:<MyReportsPage user={user}/>,
      tasks:<TasksPage user={user}/>,
      rota:<RotaPage user={user}/>,
      manager:<ManagerPortal userPerms={userPerms} setUserPerms={setUserPerms} featureUserCfg={featureUserCfg} setFeatureUserCfg={setFeatureUserCfg} permAuditLog={permAuditLog} addPermAudit={addPermAudit} currentUser={user}/>,
      subscription:<SubscriptionFeaturesPage/>,
      helpsupport:<HelpSupportPage user={user}/>,
      templates:<TemplatesPage/>,
      audit:<AuditPage/>,
      integrations:<IntegrationsPage/>,
      settings:<SettingsPage user={user}/>,
      usermgmt:<UserManagementPage plan="Growth"/>,
      finance:<FinancePage openPatient={openPatient}/>,
      huddle:<MorningHuddlePage openPatient={openPatient}/>,
      online_booking:<OnlineBookingPage setPage={p=>{setPage(p);setPatientId(null);}}/>,
      // daily_priorities: alias for nba — handled by GenericPage fallback
    };
    return PP[page]||<GenericPage page={page}/>;
  };

  if(!user)return <LoginScreen onLogin={u=>{setUser(u);setPage(u.role==="superadmin"?"admin_dash":"dashboard");}}/>;

  return <div style={{display:"flex",height:"100vh",overflow:"hidden",fontFamily:"'Inter',system-ui,sans-serif",color:C.text,background:"#071428",backgroundImage:"radial-gradient(ellipse at 20% 50%,rgba(59,130,246,0.06) 0%,transparent 50%),radial-gradient(ellipse at 80% 10%,rgba(80,140,255,0.05) 0%,transparent 45%)",WebkitFontSmoothing:"antialiased",MozOsxFontSmoothing:"grayscale",backgroundImage:"radial-gradient(ellipse at 15% 60%,rgba(0,109,255,0.05) 0%,transparent 55%),radial-gradient(ellipse at 85% 15%,rgba(80,140,255,0.04) 0%,transparent 50%)"}}>
    {alertQueue[0]&&<AlertModal patient={alertQueue[0]} onAck={ackAlert} onCancel={()=>{setAlertQueue([]);setPatientId(prevPatientId||null);setPrevPatientId(null);}}/>}
    <BusinessCopilot open={copilotOpen} onClose={()=>setCopilotOpen(false)} subscribed={copilotSubscribed} onSubscribe={()=>setCopilotSubscribed(true)}/>
    
    <Sidebar page={patientId?"patients":page} setPage={p=>{setPage(p);setPatientId(null);setAlertQueue([]);}} user={user} onLogout={()=>{setUser(null);setPage("dashboard");setPatientId(null);}} waiting={waiting} tasks={tasks} unread={notifs.filter(n=>!n.read).length} userPerms={user?userPerms[user.id]:undefined} featureUserCfg={featureUserCfg} plan="Growth"/>
    {showNewPatient&&<AddPatientModal
      onClose={()=>setShowNewPatient(false)}
      onAdd={newPat=>{setShowNewPatient(false);}}
    />}
    {showBookAppt&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.65)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:900}} onClick={()=>setShowBookAppt(false)}>
      <div style={{background:"#0F1C34",border:"1px solid rgba(80,140,255,0.3)",borderRadius:18,padding:28,maxWidth:380,width:"90%",textAlign:"center"}}>
        <div style={{fontSize:36,marginBottom:10}}>📅</div>
        <div style={{fontSize:15,fontWeight:800,color:"#F8FAFC",marginBottom:8}}>Book Appointment</div>
        <div style={{fontSize:12,color:"#CBD5E1",marginBottom:16}}>Select a time slot in the Calendar or search for a patient first.</div>
        <div style={{display:"flex",gap:10}}>
          <button onClick={()=>{setShowBookAppt(false);setPage("calendar");}} style={{flex:1,padding:"10px",background:"linear-gradient(135deg,#2563FF,#1D4ED8)",border:"none",borderRadius:10,cursor:"pointer",fontSize:12,fontWeight:700,color:"#fff",fontFamily:"inherit"}}>Open Calendar</button>
          <button onClick={()=>setShowBookAppt(false)} style={{flex:1,padding:"10px",border:"1px solid rgba(80,140,255,0.2)",borderRadius:10,background:"transparent",cursor:"pointer",fontSize:12,color:"#CBD5E1",fontFamily:"inherit"}}>Cancel</button>
        </div>
      </div>
    </div>}
    <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",background:"#071428"}}>
      <Header user={user} notifs={notifs} onClearNotifs={()=>setNotifs(p=>p.map(n=>({...n,read:true})))} onCopilot={()=>setCopilotOpen(true)} copilotSubscribed={copilotSubscribed}/>
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>{renderContent()}</div>
    </div>
  </div>;
}

// ══════════════════════════════════════════════════════════════════════════
// AUTO-GENERATED TREATMENT REPORT (previewed as styled HTML card)
// ══════════════════════════════════════════════════════════════════════════
function TreatmentReportModal({patient,teeth,txPlan,user,onClose,onSend,onSaveDoc}){
  const now=new Date();
  const dateStr=now.toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"});
  const CLABELS={miss:"Missing",filling:"Filling",crown:"Crown",rct:"Root Canal Treated",decay:"Decay/Caries",implant:"Dental Implant",extraction:"Extraction Planned",bridge:"Bridge",veneer:"Veneer",fracture:"Fracture",mobility:"Mobility",watch:"Under Observation"};
  const CCOLS={miss:"#64748B",filling:"#2563FF",crown:"#D97706",rct:"#7C3AED",decay:"#DC2626",implant:"#16A34A",extraction:"#EA580C",bridge:"#0891B2",veneer:"#DB2777",fracture:"#F97316",mobility:"#F59E0B",watch:"#CA8A04"};
  const AFCARE={crown:"Avoid hard foods for 24 hours. Sensitivity may occur — contact us if the crown feels high.",filling:"Avoid chewing on the filled tooth for 2 hours. Sensitivity to hot/cold is normal and should settle.",extraction:"Bite on gauze for 30 min. No rinsing for 24 hours. Eat soft foods only. Take pain relief as needed.",rct:"Take prescribed medication as directed. Avoid biting on the tooth until permanently restored.",implant:"Eat soft foods and avoid the implant site. Keep area clean with gentle rinsing.",default:"Maintain good oral hygiene. Brush twice daily with fluoride toothpaste. Attend regular check-ups."};
  const [saved,setSaved]=useState(false);
  const [step,setStep]=useState("preview");
  const findings=Object.entries(teeth||{}).filter(([n,d])=>d.cond||d.planned?.length||d.completed?.length).map(([n,d])=>{const q=Math.floor(parseInt(n)/10);const pal=({1:"UR",2:"UL",3:"LL",4:"LR"}[q]||"")+String(parseInt(n)%10);return{n,pal,cond:d.cond,planned:d.planned,completed:d.completed};});
  const doneTx=(txPlan||[]).filter(t=>t.status==="completed");
  const planTx=(txPlan||[]).filter(t=>t.status==="planned");
  const total=doneTx.reduce((s,t)=>s+(t.fee||0),0);
  const mainConds=[...new Set(findings.map(f=>f.cond).filter(Boolean))];
  const aftercare=AFCARE[mainConds[0]]||AFCARE.default;
  const doSend=()=>{setStep("sending");setSaved(true);onSaveDoc?.({name:`TreatmentReport_${now.toISOString().slice(0,10)}.pdf`,date:dateStr,type:"Treatment Report",by:user?.name||"Dr. S. Patel",icon:"📋",sent:true});setTimeout(()=>{setStep("done");onSend?.({type:"Treatment Report",trigger:"doctor"});},1200);};
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",display:"flex",alignItems:"flex-start",justifyContent:"center",zIndex:995,overflowY:"auto",padding:"20px 0"}} onClick={e=>{if(e.target===e.currentTarget)onClose?.();}}>
      <div style={{background:"#F8FAFC",borderRadius:16,width:680,maxWidth:"95vw",overflow:"hidden",boxShadow:"0 32px 80px rgba(0,0,0,0.6)",margin:"auto"}}>
        <div style={{background:"linear-gradient(135deg,#071428,#0F1C34)",padding:"18px 26px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{display:"flex",gap:12,alignItems:"center"}}>
            <div style={{width:44,height:44,borderRadius:12,background:"linear-gradient(135deg,#2563FF,#1D4ED8)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22}}>🦷</div>
            <div><div style={{fontSize:15,fontWeight:800}}><span style={{color:"#F8FAFC"}}>ProDental</span><span style={{color:"#3B82F6"}}>Connect</span></div><div style={{fontSize:10,color:"#CBD5E1"}}>Riverside Dentistry · 14 High Street, East Molesey KT8 9RD</div></div>
          </div>
          <div style={{textAlign:"right"}}><div style={{fontSize:11,fontWeight:700,color:"#F8FAFC"}}>TREATMENT REPORT</div><div style={{fontSize:10,color:"#94A3B8"}}>{dateStr}</div></div>
        </div>
        <div style={{padding:"20px 26px",background:"#fff",color:"#1e293b"}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,marginBottom:18,padding:"12px 14px",background:"#f8fafc",borderRadius:10,border:"1px solid #e2e8f0",fontSize:12}}>
            <div><div style={{fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase",marginBottom:2}}>Patient</div><div style={{fontWeight:700,color:"#0f172a"}}>{patient?.name}</div></div>
            <div><div style={{fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase",marginBottom:2}}>Clinician</div><div style={{color:"#0f172a"}}>{user?.name||"Dr. S. Patel"}</div></div>
            <div><div style={{fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase",marginBottom:2}}>NHS Number</div><div style={{color:"#0f172a"}}>{patient?.nhs||"Private"}</div></div>
            <div><div style={{fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase",marginBottom:2}}>Date</div><div style={{color:"#0f172a"}}>{dateStr}</div></div>
          </div>
          {findings.length>0&&<><div style={{fontSize:12,fontWeight:700,marginBottom:8,borderBottom:"1.5px solid #e2e8f0",paddingBottom:4}}>🦷 Dental Chart Findings</div><div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:16}}>{findings.map(f=>{const c=CCOLS[f.cond]||"#64748B";return(<div key={f.n} style={{padding:"3px 10px",borderRadius:20,border:`1.5px solid ${c}`,background:c+"14",fontSize:11,fontWeight:700,color:c}}><span style={{color:"#1e293b",fontWeight:800}}>{f.pal}</span>{CLABELS[f.cond]&&<span> — {CLABELS[f.cond]}</span>}</div>);})}</div></>}
          {doneTx.length>0&&<><div style={{fontSize:12,fontWeight:700,marginBottom:8,borderBottom:"1.5px solid #e2e8f0",paddingBottom:4}}>✅ Treatment Provided</div><table style={{width:"100%",borderCollapse:"collapse",marginBottom:16,fontSize:12}}><thead><tr style={{background:"#f1f5f9"}}><th style={{padding:"6px 10px",textAlign:"left",fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase"}}>Treatment</th><th style={{padding:"6px 10px",textAlign:"left",fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase"}}>Teeth</th><th style={{padding:"6px 10px",textAlign:"right",fontSize:9,fontWeight:700,color:"#64748B",textTransform:"uppercase"}}>Fee</th></tr></thead><tbody>{doneTx.map((t,i)=>(<tr key={t.id} style={{borderTop:"1px solid #e2e8f0",background:i%2?"#f8fafc":"#fff"}}><td style={{padding:"6px 10px",fontWeight:600}}>{t.label}</td><td style={{padding:"6px 10px",color:"#475569"}}>{t.teeth?.join(", ")||"—"}</td><td style={{padding:"6px 10px",textAlign:"right",fontFamily:"ui-monospace,monospace",fontWeight:700}}>£{(t.fee||0).toFixed(2)}</td></tr>))}<tr style={{background:"#f1f5f9",fontWeight:800}}><td colSpan={2} style={{padding:"6px 10px"}}>Total</td><td style={{padding:"6px 10px",textAlign:"right",fontFamily:"ui-monospace,monospace"}}>£{total.toFixed(2)}</td></tr></tbody></table></>}
          {planTx.length>0&&<><div style={{fontSize:12,fontWeight:700,marginBottom:8,borderBottom:"1.5px solid #e2e8f0",paddingBottom:4}}>📋 Outstanding Treatment Plan</div><div style={{marginBottom:16}}>{planTx.map(t=>(<div key={t.id} style={{display:"flex",justifyContent:"space-between",padding:"6px 10px",background:"#fefce8",border:"1px solid #fde68a",borderRadius:7,marginBottom:4,fontSize:12}}><span style={{color:"#92400e",fontWeight:600}}>{t.label}</span><span style={{fontFamily:"ui-monospace,monospace",color:"#92400e",fontWeight:700}}>£{(t.fee||0).toFixed(2)}</span></div>))}</div></>}
          <div style={{padding:"12px 14px",background:"#eff6ff",border:"1px solid #bfdbfe",borderRadius:10,marginBottom:16}}><div style={{fontSize:10,fontWeight:700,color:"#1d4ed8",marginBottom:4}}>💊 Aftercare Instructions</div><div style={{fontSize:12,color:"#1e3a5f",lineHeight:1.65}}>{aftercare}</div></div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:10,color:"#94A3B8",borderTop:"1px solid #e2e8f0",paddingTop:8}}>
            <span>Riverside Dentistry · CQC-ENG-DENT-44190 · Generated by ProDentalConnect</span><span>Page 1</span>
          </div>
        </div>
        <div style={{padding:"12px 22px",background:"#f8fafc",borderTop:"1px solid #e2e8f0",display:"flex",gap:9,justifyContent:"flex-end",alignItems:"center"}}>
          {saved&&<span style={{fontSize:11,color:"#16a34a",fontWeight:700,flex:1}}>✓ Saved to patient Documents</span>}
          <button onClick={onClose} style={{padding:"9px 18px",border:"1px solid #e2e8f0",borderRadius:9,background:"#fff",cursor:"pointer",fontSize:12,fontWeight:600,color:"#475569",fontFamily:"inherit"}}>Close</button>
          <button onClick={doSend} disabled={step!=="preview"} style={{padding:"9px 22px",background:step==="done"?"#16a34a":"linear-gradient(135deg,#2563FF,#1D4ED8)",border:"none",borderRadius:9,cursor:step!=="preview"?"default":"pointer",fontSize:12,fontWeight:800,color:"#fff",fontFamily:"inherit",display:"flex",gap:6,alignItems:"center",boxShadow:"0 2px 10px rgba(37,99,255,0.3)"}}>
            {step==="sending"?"Sending…":step==="done"?"✓ Sent":"📧 Send to Patient"}
          </button>
        </div>
      </div>
    </div>
  );
}


