// ── Signature Canvas ─────────────────────────────────────────────────────────
function SignatureCanvas({onSave,onClear}){
  const canvasRef=useRef(null);
  const [drawing,setDrawing]=useState(false);
  const [hasStroke,setHasStroke]=useState(false);
  const lastPt=useRef(null);

  const getPos=(e,canvas)=>{
    const r=canvas.getBoundingClientRect();
    const t=e.touches?e.touches[0]:e;
    return{x:t.clientX-r.left,y:t.clientY-r.top};
  };

  const startDraw=(e)=>{
    e.preventDefault();
    const canvas=canvasRef.current;if(!canvas)return;
    const ctx=canvas.getContext("2d");
    const pt=getPos(e,canvas);
    ctx.beginPath();ctx.moveTo(pt.x,pt.y);
    setDrawing(true);setHasStroke(true);lastPt.current=pt;
  };
  const draw=(e)=>{
    e.preventDefault();
    if(!drawing)return;
    const canvas=canvasRef.current;if(!canvas)return;
    const ctx=canvas.getContext("2d");
    const pt=getPos(e,canvas);
    ctx.lineWidth=2;ctx.lineCap="round";ctx.strokeStyle="#1e293b";
    ctx.lineTo(pt.x,pt.y);ctx.stroke();lastPt.current=pt;
  };
  const endDraw=(e)=>{
    e.preventDefault();setDrawing(false);
    if(hasStroke&&canvasRef.current)onSave?.(canvasRef.current.toDataURL());
  };
  const clear=()=>{
    const canvas=canvasRef.current;if(!canvas)return;
    canvas.getContext("2d").clearRect(0,0,canvas.width,canvas.height);
    setHasStroke(false);onClear?.();
  };

  return(
    <div>
      <canvas ref={canvasRef} width={420} height={120}
        style={{border:"2px solid #3B82F6",borderRadius:10,background:"#f8fafc",cursor:"crosshair",display:"block",touchAction:"none"}}
        onMouseDown={startDraw} onMouseMove={draw} onMouseUp={endDraw} onMouseLeave={endDraw}
        onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={endDraw}/>
      <button onClick={clear} style={{marginTop:6,padding:"4px 12px",border:"1px solid #e2e8f0",borderRadius:6,background:"#fff",cursor:"pointer",fontSize:11,color:"#64748B",fontFamily:"inherit"}}>Clear</button>
    </div>
  );
}

// ── Consent Form Modal (iPad / Reception / Online) ───────────────────────────
function ConsentFormModal({template,patient,mode,onClose,onSubmit}){
  const [answers,setAnswers]=useState({});
  const [sig,setSig]=useState(null);
  const [submitted,setSubmitted]=useState(false);
  const [step,setStep]=useState(0);
  const t=template||CONSENT_TEMPLATES[0];
  const sigFields=t.fields.filter(f=>f.type==="signature");
  const allRequired=t.fields.filter(f=>f.required);
  const allDone=allRequired.every(f=>f.type==="signature"?!!sig:f.type==="checkbox"?answers[f.id]===true:true);

  const submit=()=>{
    const entry={
      id:"CF"+Date.now(),templateId:t.id,title:t.title,
      patientId:patient?.id,patientName:patient?.name,
      signedAt:new Date().toISOString(),
      signature:sig,device:mode||"reception",
      answers,status:"signed",
      sentBy:"Staff",version:"1.0",
    };
    onSubmit?.(entry);
    setSubmitted(true);
  };

  if(submitted)return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
      <div style={{background:"#0F1C34",border:"1px solid rgba(80,140,255,0.3)",borderRadius:20,padding:40,textAlign:"center",maxWidth:400}}>
        <div style={{fontSize:48,marginBottom:12}}>✅</div>
        <div style={{fontSize:18,fontWeight:800,color:"#F8FAFC",marginBottom:8}}>Form Signed</div>
        <div style={{fontSize:12,color:"#CBD5E1",marginBottom:20}}>Saved to patient records. The doctor can view this immediately.</div>
        <button onClick={onClose} style={{padding:"11px 32px",background:"linear-gradient(135deg,#2563FF,#1D4ED8)",border:"none",borderRadius:11,cursor:"pointer",fontSize:13,fontWeight:700,color:"#fff",fontFamily:"inherit"}}>Done</button>
      </div>
    </div>
  );

  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",display:"flex",alignItems:"flex-start",justifyContent:"center",zIndex:1000,overflowY:"auto",padding:"20px 0"}} onClick={e=>{if(e.target===e.currentTarget)onClose?.();}}>
      <div style={{background:"#0F1C34",border:"1px solid rgba(80,140,255,0.3)",borderRadius:20,width:520,maxWidth:"95vw",overflow:"hidden",boxShadow:"0 32px 80px rgba(0,0,0,0.6)",margin:"auto"}}>
        <div style={{background:"linear-gradient(135deg,#071428,#0F1C34)",padding:"18px 24px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div>
            <div style={{fontSize:15,fontWeight:800,color:"#F8FAFC"}}>{t.title}</div>
            <div style={{fontSize:11,color:"#CBD5E1"}}>Riverside Dentistry · {patient?.name||"Patient"}</div>
          </div>
          <button onClick={onClose} style={{border:"none",background:"transparent",cursor:"pointer",color:"#94A3B8",fontSize:20}}>✕</button>
        </div>
        <div style={{padding:"20px 24px"}}>
          {t.fields.map((f,i)=>(
            <div key={f.id} style={{marginBottom:16}}>
              {f.type==="info"&&<div style={{padding:"10px 14px",background:"rgba(59,130,246,0.08)",border:"1px solid rgba(80,140,255,0.2)",borderRadius:10,fontSize:12,color:"#CBD5E1",lineHeight:1.6}}>{f.label}</div>}
              {f.type==="checkbox"&&<label style={{display:"flex",gap:10,alignItems:"flex-start",cursor:"pointer"}}>
                <div onClick={()=>setAnswers(p=>({...p,[f.id]:!p[f.id]}))} style={{width:20,height:20,borderRadius:5,border:`2px solid ${answers[f.id]?"#2563FF":"rgba(80,140,255,0.3)"}`,background:answers[f.id]?"#2563FF":"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,marginTop:1,cursor:"pointer"}}>
                  {answers[f.id]&&<span style={{color:"#fff",fontSize:13,fontWeight:700}}>✓</span>}
                </div>
                <span style={{fontSize:12,color:"#CBD5E1",lineHeight:1.6}}>{f.label}{f.required&&<span style={{color:"#EF4444",marginLeft:2}}>*</span>}</span>
              </label>}
              {f.type==="text"&&<div>
                <div style={{fontSize:11,fontWeight:600,color:"#CBD5E1",marginBottom:5}}>{f.label}</div>
                <input value={answers[f.id]||""} onChange={e=>setAnswers(p=>({...p,[f.id]:e.target.value}))} style={{width:"100%",padding:"9px 12px",background:"#132238",border:"1.5px solid rgba(80,140,255,0.25)",borderRadius:9,color:"#F8FAFC",fontSize:12,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}/>
              </div>}
              {f.type==="signature"&&<div>
                <div style={{fontSize:11,fontWeight:700,color:"#CBD5E1",marginBottom:6}}>{f.label}<span style={{color:"#EF4444",marginLeft:2}}>*</span></div>
                <div style={{padding:"12px",background:"#fff",borderRadius:12,display:"inline-block"}}>
                  <SignatureCanvas onSave={setSig} onClear={()=>setSig(null)}/>
                </div>
                {sig&&<div style={{fontSize:10,color:"#4ADE80",marginTop:4}}>✓ Signature captured</div>}
              </div>}
            </div>
          ))}
          <div style={{fontSize:10,color:"#94A3B8",marginBottom:14,padding:"8px 12px",background:"rgba(2,8,23,0.4)",borderRadius:8}}>
            Signed digitally · {new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"})} · {mode==="ipad"?"iPad (Reception)":mode==="portal"?"Patient Portal":"Reception computer"}
          </div>
          <button onClick={submit} disabled={!allDone}
            style={{width:"100%",padding:"13px",background:allDone?"linear-gradient(135deg,#2563FF,#1D4ED8)":"rgba(80,140,255,0.15)",border:allDone?"none":"1px solid rgba(80,140,255,0.2)",borderRadius:12,cursor:allDone?"pointer":"not-allowed",fontSize:14,fontWeight:800,color:allDone?"#fff":"#64748B",fontFamily:"inherit",boxShadow:allDone?"0 2px 14px rgba(37,99,255,0.35)":"none"}}>
            {allDone?"Sign & Submit Form":"Please complete all required fields above"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Consent Forms Manager (in patient record) ────────────────────────────────
function ConsentFormsPanel({patient,user}){
  const [forms,setForms]=useState([
    {id:"CF001",title:"General Treatment Consent",status:"signed",signedAt:"2025-05-14T09:00:00Z",device:"ipad",patientName:patient?.name},
    {id:"CF002",title:"Medical History Form",status:"pending",sentAt:"2025-05-13T14:00:00Z",email:patient?.email},
  ]);
  const [showModal,setShowModal]=useState(null);
  const [toast,setToast]=useState(null);
  const doToast=m=>{setToast(m);setTimeout(()=>setToast(null),2500);};

  const sendLink=(form)=>{
    doToast(`✓ Consent form link sent to ${patient?.email||"patient"}`);
    setForms(p=>p.map(f=>f.id===form.id?{...f,status:"link_sent",sentAt:new Date().toISOString(),email:patient?.email}:f));
  };

  const statusBadge=(status)=>{
    const s={signed:{c:"#4ADE80",bg:"rgba(34,197,94,0.12)",l:"Signed"},pending:{c:"#FCD34D",bg:"rgba(245,158,11,0.12)",l:"Pending"},link_sent:{c:"#60A5FA",bg:"rgba(59,130,246,0.12)",l:"Link Sent"}};
    const st=s[status]||s.pending;
    return(<span style={{fontSize:9,fontWeight:700,padding:"2px 8px",borderRadius:20,background:st.bg,color:st.c,border:`1px solid ${st.c}30`}}>{st.l}</span>);
  };

  return(
    <div style={{flex:1,overflowY:"auto",background:"#071428",padding:20}}>
      {toast&&<div style={{position:"fixed",top:64,right:18,padding:"10px 18px",background:"#0F1C34",border:"1px solid rgba(80,140,255,0.3)",borderRadius:12,fontSize:12,color:"#4ADE80",zIndex:600}}>✓ {toast}</div>}
      {showModal&&<ConsentFormModal
        template={CONSENT_TEMPLATES.find(t=>t.id===showModal)}
        patient={patient} mode="reception"
        onClose={()=>setShowModal(null)}
        onSubmit={entry=>{setForms(p=>[{...entry,id:"CF"+Date.now(),status:"signed"},...p]);setShowModal(null);doToast("Consent form signed and saved");}}
      />}

      <div style={{maxWidth:900}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <div>
            <div style={{fontSize:14,fontWeight:700,color:"#F8FAFC"}}>Consent Forms</div>
            <div style={{fontSize:11,color:"#CBD5E1",marginTop:2}}>Digital forms for {patient?.name}</div>
          </div>
          <div style={{display:"flex",gap:8}}>
            <button onClick={()=>doToast(`Form link sent to ${patient?.email||"patient"}`)}
              style={{padding:"8px 16px",background:"rgba(59,130,246,0.1)",border:"1px solid rgba(80,140,255,0.28)",borderRadius:10,cursor:"pointer",fontSize:12,fontWeight:700,color:"#60A5FA",fontFamily:"inherit",display:"flex",gap:6,alignItems:"center"}}>
              📧 Send Link
            </button>
            <button onClick={()=>setShowModal("C5")}
              style={{padding:"8px 16px",background:"linear-gradient(135deg,#2563FF,#1D4ED8)",border:"none",borderRadius:10,cursor:"pointer",fontSize:12,fontWeight:700,color:"#fff",fontFamily:"inherit",display:"flex",gap:6,alignItems:"center",boxShadow:"0 2px 8px rgba(37,99,255,0.3)"}}>
              📋 Open on iPad
            </button>
          </div>
        </div>

        {/* Existing forms */}
        <div style={{background:"#0F1C34",border:"1px solid rgba(80,140,255,0.2)",borderRadius:14,overflow:"hidden",marginBottom:16}}>
          {forms.map((f,i)=>(
            <div key={f.id} style={{display:"flex",gap:12,alignItems:"center",padding:"12px 16px",borderBottom:i<forms.length-1?"1px solid rgba(80,140,255,0.1)":"none"}}>
              <div style={{width:36,height:36,borderRadius:10,background:f.status==="signed"?"rgba(34,197,94,0.12)":"rgba(245,158,11,0.1)",border:`1px solid ${f.status==="signed"?"rgba(34,197,94,0.25)":"rgba(245,158,11,0.25)"}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>
                {f.status==="signed"?"✅":"📋"}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC",display:"flex",gap:8,alignItems:"center"}}>
                  {f.title} {statusBadge(f.status)}
                </div>
                <div style={{fontSize:10,color:"#94A3B8",marginTop:2}}>
                  {f.status==="signed"?`Signed ${new Date(f.signedAt).toLocaleString("en-GB",{day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"})} · ${f.device==="ipad"?"iPad":"Online"}`:
                   f.sentAt?`Sent ${new Date(f.sentAt).toLocaleString("en-GB",{day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"})} to ${f.email||"patient"}`:"Awaiting signature"}
                </div>
              </div>
              {f.status==="signed"?
                <button style={{padding:"5px 12px",border:"1px solid rgba(80,140,255,0.2)",borderRadius:7,background:"transparent",cursor:"pointer",fontSize:10,color:"#60A5FA",fontFamily:"inherit"}}>View PDF</button>:
                <button onClick={()=>sendLink(f)} style={{padding:"5px 12px",border:"1px solid rgba(245,158,11,0.3)",borderRadius:7,background:"rgba(245,158,11,0.08)",cursor:"pointer",fontSize:10,color:"#FCD34D",fontFamily:"inherit"}}>Resend</button>
              }
            </div>
          ))}
        </div>

        {/* Add new forms */}
        <div style={{fontSize:11,fontWeight:700,color:"#CBD5E1",marginBottom:10,textTransform:"uppercase",letterSpacing:".05em"}}>Add consent form</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:8}}>
          {CONSENT_TEMPLATES.map(t=>(
            <button key={t.id} onClick={()=>setShowModal(t.id)} style={{padding:"12px 14px",background:"#132238",border:"1px solid rgba(80,140,255,0.18)",borderRadius:12,cursor:"pointer",textAlign:"left",fontFamily:"inherit"}}>
              <div style={{fontSize:12,fontWeight:700,color:"#F8FAFC",marginBottom:3}}>{t.title}</div>
              <div style={{fontSize:10,color:"#94A3B8"}}>Click to open on iPad</div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── iPad Kiosk Mode ──────────────────────────────────────────────────────────
